                      APPLICATION DEVELOPED BY KAZEHUNT
                  </div>
                  <div className="text-[#4a5f78] font-orbitron text-[9px] leading-relaxed tracking-[0.1em] uppercase max-w-2xl flex flex-col gap-2">
                      <p>DESIGNED EXCLUSIVELY FOR HONOR OF KINGS CUSTOM FUN MATCHES ON THE OFFICIAL DISCORD. THE DEVELOPER ASSUMES NO RESPONSIBILITY FOR USAGE OUTSIDE THIS INTENDED SCOPE.</p>
                  </div>
              </div>
          </footer>
        </>
      )}

      {currentMatch && viewMode !== 'lobby' && (
        <MatchDisplay 
          match={currentMatch} 
          activePlayers={activePlayers} 
          initialMode={viewMode === 'battle' ? 'battle' : 'draft'}
          onReset={() => { setCurrentMatch(null); setViewMode('lobby'); }}
          onCompleteMatch={handleMatchFinish}
          onReroll={handleRerollSlot}
          onStartBattle={() => setViewMode('battle')}
        />
      )}
      <style>{`
        @keyframes chromatic {
          0% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
          25% { text-shadow: -2px 0 0 #ff0000, 2px 0 0 #0000ff; }
          50% { text-shadow: 2px -1px 0 #ff0000, -2px 1px 0 #0000ff; }
          75% { text-shadow: -2px 1px 0 #ff0000, 2px -1px 0 #0000ff; }
          100% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
        }
      `}</style>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';

export const CustomCursor: React.FC = () => {
  const [position, setPosition] = useState({ x: -100, y: -100 });
  const [isPointer, setIsPointer] = useState(false);
  const [isInput, setIsInput] = useState(false);
  const [isMouseDown, setIsMouseDown] = useState(false);
  const [isVisible, setIsVisible] = useState(false);

  const dotRef = useRef<HTMLDivElement>(null);
  const ringRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      setPosition({ x: e.clientX, y: e.clientY });
      setIsVisible(true);

      const target = e.target as HTMLElement;
      const isClickable = window.getComputedStyle(target).cursor === 'pointer' || 
                          target.tagName === 'BUTTON' || 
                          target.closest('button') || 
                          target.tagName === 'A';

      const isInputField = target.tagName === 'INPUT' || 
                           target.tagName === 'TEXTAREA' || 
                           target.isContentEditable;

      setIsPointer(!!isClickable);
      setIsInput(!!isInputField);
    };

    const onMouseDown = () => setIsMouseDown(true);
    const onMouseUp = () => setIsMouseDown(false);
    const onMouseLeave = () => setIsVisible(false);
    const onMouseEnter = () => setIsVisible(true);

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mousedown', onMouseDown);
    window.addEventListener('mouseup', onMouseUp);
    document.addEventListener('mouseleave', onMouseLeave);
    document.addEventListener('mouseenter', onMouseEnter);

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mousedown', onMouseDown);
      window.removeEventListener('mouseup', onMouseUp);
      document.removeEventListener('mouseleave', onMouseLeave);
      document.removeEventListener('mouseenter', onMouseEnter);
    };
  }, []);

  if (!isVisible) return null;

  return (
    <div className="fixed inset-0 pointer-events-none z-[99999] hidden lg:block">
      {/* Outer Ring */}
      <div 
        ref={ringRef}
        style={{ 
          left: position.x, 
          top: position.y,
          transform: `translate(-50%, -50%) scale(${isMouseDown ? 0.8 : (isPointer ? 1.5 : (isInput ? 0.4 : 1))})`,
        }}
        className={`absolute w-10 h-10 border-2 rounded-full transition-transform duration-300 ease-out flex items-center justify-center
          ${isPointer ? 'border-[#dcb06b] shadow-[0_0_15px_#dcb06b]' : 'border-[#dcb06b]/40'}
          ${isInput ? 'h-12 w-2 rounded-none border-x-2 border-y-0' : ''}
        `}
      >
        {/* Decorative spinning segments */}
        {!isInput && (
          <div className={`absolute inset-0 border-t-2 border-b-2 border-transparent border-t-[#dcb06b] border-b-[#dcb06b] rounded-full animate-spin-slow opacity-60 ${isPointer ? 'animate-[spin_1s_linear_infinite]' : ''}`}></div>
        )}
      </div>

      {/* Center Dot */}
      <div 
        ref={dotRef}
        style={{ 
          left: position.x, 
          top: position.y,
          transform: 'translate(-50%, -50%)'
        }}
        className={`absolute w-1.5 h-1.5 bg-[#dcb06b] rounded-full transition-all duration-100
          ${isMouseDown ? 'scale-75' : 'scale-100'}
          ${isPointer ? 'w-2 h-2 shadow-[0_0_10px_#dcb06b]' : ''}
          ${isInput ? 'h-6 w-[2px] rounded-none' : ''}
        `}
      />

      {/* Click Ripple Effect (Visual indicator on click) */}
      <style>{`
        body, button, input, textarea, a, [role="button"] {
          cursor: none !important;
        }
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
};

