import React, { useState, useEffect, useRef } from 'react';

export const CustomCursor: React.FC = () => {
  const [position, setPosition] = useState({ x: -100, y: -100 });
  const [isPointer, setIsPointer] = useState(false);
  const [isInput, setIsInput] = useState(false);
  const [isMouseDown, setIsMouseDown] = useState(false);
  const [isVisible, setIsVisible] = useState(false);

  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      setPosition({ x: e.clientX, y: e.clientY });
      setIsVisible(true);

      const target = e.target as HTMLElement;
      const isClickable = window.getComputedStyle(target).cursor === 'pointer' || 
                          target.tagName === 'BUTTON' || 
                          target.closest('button') || 
                          target.tagName === 'A' ||
                          target.getAttribute('role') === 'button';

      const isInputField = target.tagName === 'INPUT' || 
                           target.tagName === 'TEXTAREA' || 
                           target.isContentEditable;

      setIsPointer(!!isClickable);
      setIsInput(!!isInputField);
    };

    const onMouseDown = () => setIsMouseDown(true);
    const onMouseUp = () => setIsMouseDown(false);
    const onMouseLeave = () => setIsVisible(false);
    const onMouseEnter = () => setIsVisible(true);

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mousedown', onMouseDown);
    window.addEventListener('mouseup', onMouseUp);
    document.addEventListener('mouseleave', onMouseLeave);
    document.addEventListener('mouseenter', onMouseEnter);

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mousedown', onMouseDown);
      window.removeEventListener('mouseup', onMouseUp);
      document.removeEventListener('mouseleave', onMouseLeave);
      document.removeEventListener('mouseenter', onMouseEnter);
    };
  }, []);

  if (!isVisible) return null;

  // Adaptive scale and color
  const currentScale = isMouseDown ? 0.75 : (isPointer ? 1.4 : (isInput ? 0.6 : 1));
  const activeColor = isPointer ? '#dcb06b' : (isInput ? '#ffffff' : '#dcb06b');
  const glowIntensity = isPointer ? '0 0 15px rgba(220, 176, 107, 0.8)' : (isInput ? '0 0 10px rgba(255, 255, 255, 0.5)' : 'none');

  return (
    <div className="fixed inset-0 pointer-events-none z-[99999] hidden lg:block">
      {/* Tech Brackets Container */}
      <div 
        ref={containerRef}
        style={{ 
          left: position.x, 
          top: position.y,
          transform: `translate(-50%, -50%) scale(${currentScale})`,
          width: isInput ? '12px' : '32px',
          height: isInput ? '48px' : '32px',
          transition: 'transform 0.15s cubic-bezier(0.175, 0.885, 0.32, 1.275), width 0.3s ease, height 0.3s ease'
        }}
        className="absolute flex items-center justify-center"
      >
        {/* Corner Brackets - Square Model */}
        {!isInput && (
          <>
            {/* Top Left */}
            <div className="absolute top-0 left-0 w-2 h-2 border-t-2 border-l-2" style={{ borderColor: activeColor, boxShadow: glowIntensity }}></div>
            {/* Top Right */}
            <div className="absolute top-0 right-0 w-2 h-2 border-t-2 border-r-2" style={{ borderColor: activeColor, boxShadow: glowIntensity }}></div>
            {/* Bottom Left */}
            <div className="absolute bottom-0 left-0 w-2 h-2 border-b-2 border-l-2" style={{ borderColor: activeColor, boxShadow: glowIntensity }}></div>
            {/* Bottom Right */}
            <div className="absolute bottom-0 right-0 w-2 h-2 border-b-2 border-r-2" style={{ borderColor: activeColor, boxShadow: glowIntensity }}></div>

            {/* Rotating Tech Cross */}
            <div 
              className={`absolute w-full h-full opacity-20 border border-dashed rounded-sm transition-all duration-700 ${isPointer ? 'rotate-45 scale-125 opacity-40' : 'rotate-0'}`}
              style={{ borderColor: activeColor }}
            ></div>
          </>
        )}

        {/* Input Cursor Lines */}
        {isInput && (
          <>
            <div className="absolute top-0 w-full h-[2px] bg-white"></div>
            <div className="absolute bottom-0 w-full h-[2px] bg-white"></div>
            <div className="h-2/3 w-[2px] bg-white animate-pulse"></div>
          </>
        )}

        {/* Center Tech Dot */}
        <div 
          className={`absolute w-1 h-1 bg-[#dcb06b] transition-all duration-300 ${isMouseDown ? 'scale-150' : ''} ${isPointer ? 'scale-0' : 'scale-100'}`}
          style={{ boxShadow: glowIntensity }}
        />
      </div>

      <style>{`
        body, button, input, textarea, a, [role="button"] {
          cursor: none !important;
        }
      `}</style>
    </div>
  );
};

