import React, { useState, useEffect, useRef } from 'react';

export const CustomCursor: React.FC = () => {
  const [position, setPosition] = useState({ x: -100, y: -100 });
  const [isPointer, setIsPointer] = useState(false);
  const [isInput, setIsInput] = useState(false);
  const [isMouseDown, setIsMouseDown] = useState(false);
  const [isVisible, setIsVisible] = useState(false);

  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      setPosition({ x: e.clientX, y: e.clientY });
      setIsVisible(true);

      const target = e.target as HTMLElement;
      const isClickable = window.getComputedStyle(target).cursor === 'pointer' || 
                          target.tagName === 'BUTTON' || 
                          target.closest('button') || 
                          target.tagName === 'A' ||
                          target.getAttribute('role') === 'button';

      const isInputField = target.tagName === 'INPUT' || 
                           target.tagName === 'TEXTAREA' || 
                           target.isContentEditable;

      setIsPointer(!!isClickable);
      setIsInput(!!isInputField);
    };

    const onMouseDown = () => setIsMouseDown(true);
    const onMouseUp = () => setIsMouseDown(false);
    const onMouseLeave = () => setIsVisible(false);
    const onMouseEnter = () => setIsVisible(true);

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mousedown', onMouseDown);
    window.addEventListener('mouseup', onMouseUp);
    document.addEventListener('mouseleave', onMouseLeave);
    document.addEventListener('mouseenter', onMouseEnter);

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mousedown', onMouseDown);
      window.removeEventListener('mouseup', onMouseUp);
      document.removeEventListener('mouseleave', onMouseLeave);
      document.removeEventListener('mouseenter', onMouseEnter);
    };
  }, []);

  if (!isVisible) return null;

  // Adaptive values
  const currentScale = isMouseDown ? 0.75 : (isPointer ? 1.5 : (isInput ? 0.8 : 1));
  const activeColor = isPointer ? '#dcb06b' : (isInput ? '#ffffff' : '#dcb06b');
  const glowIntensity = isPointer ? '0 0 20px rgba(220, 176, 107, 0.9)' : (isInput ? '0 0 10px rgba(255, 255, 255, 0.6)' : 'none');

  return (
    <div className="fixed inset-0 pointer-events-none z-[99999] hidden lg:block">
      {/* Target Bracket Container */}
      <div 
        ref={containerRef}
        style={{ 
          left: position.x, 
          top: position.y,
          transform: `translate(-50%, -50%) scale(${currentScale})`,
          width: isInput ? '10px' : '40px',
          height: isInput ? '50px' : '40px',
          transition: 'transform 0.1s cubic-bezier(0.175, 0.885, 0.32, 1.275), width 0.25s ease, height 0.25s ease'
        }}
        className="absolute flex items-center justify-center"
      >
        {/* Corner Brackets */}
        {!isInput && (
          <>
            {/* Top Left */}
            <div className="absolute top-0 left-0 w-3 h-3 border-t-4 border-l-4" style={{ borderColor: activeColor, boxShadow: glowIntensity }}></div>
            {/* Top Right */}
            <div className="absolute top-0 right-0 w-3 h-3 border-t-4 border-r-4" style={{ borderColor: activeColor, boxShadow: glowIntensity }}></div>
            {/* Bottom Left */}
            <div className="absolute bottom-0 left-0 w-3 h-3 border-b-4 border-l-4" style={{ borderColor: activeColor, boxShadow: glowIntensity }}></div>
            {/* Bottom Right */}
            <div className="absolute bottom-0 right-0 w-3 h-3 border-b-4 border-r-4" style={{ borderColor: activeColor, boxShadow: glowIntensity }}></div>

            {/* Crosshair lines inside */}
            <div className={`absolute w-[60%] h-[1px] bg-white/20 transition-opacity duration-300 ${isPointer ? 'opacity-100 scale-x-125' : 'opacity-0'}`}></div>
            <div className={`absolute h-[60%] w-[1px] bg-white/20 transition-opacity duration-300 ${isPointer ? 'opacity-100 scale-y-125' : 'opacity-0'}`}></div>
          </>
        )}

        {/* Input Morph: Tech Bar */}
        {isInput && (
          <div className="relative h-full w-full flex flex-col justify-between items-center">
             <div className="w-full h-1 bg-white shadow-[0_0_10px_white]"></div>
             <div className="h-[60%] w-[2px] bg-white animate-pulse"></div>
             <div className="w-full h-1 bg-white shadow-[0_0_10px_white]"></div>
          </div>
        )}

        {/* Core Tech Node */}
        <div 
          className={`absolute w-1.5 h-1.5 bg-[#dcb06b] transition-all duration-300 ${isMouseDown ? 'scale-150 shadow-[0_0_15px_#dcb06b]' : ''} ${isPointer ? 'rotate-45 scale-125' : 'scale-100'}`}
          style={{ 
            clipPath: !isInput ? 'polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%)' : 'none',
            opacity: isInput ? 0 : 1
          }}
        />
      </div>

      <style>{`
        body, button, input, textarea, a, [role="button"], label {
          cursor: none !important;
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';

export const LocalClock: React.FC = () => {
  const [time, setTime] = useState('');
  const [isVisible, setIsVisible] = useState(true);
  const [isMinimized, setIsMinimized] = useState(false);
  const [position, setPosition] = useState({ x: window.innerWidth - 150, y: 20 });
  const [isDragging, setIsDragging] = useState(false);
  const dragOffset = useRef({ x: 0, y: 0 });

  useEffect(() => {
    const updateTime = () => {
      const now = new Date();
      const options: Intl.DateTimeFormatOptions = {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: false,
      };
      // Uses local system time automatically by omitting timeZone
      setTime(new Intl.DateTimeFormat(undefined, options).format(now));
    };

    updateTime();
    const interval = setInterval(updateTime, 1000);
    return () => clearInterval(interval);
  }, []);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isMinimized) return;
    setIsDragging(true);
    dragOffset.current = {
      x: e.clientX - position.x,
      y: e.clientY - position.y
    };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;

      const newX = Math.max(0, Math.min(window.innerWidth - (isMinimized ? 40 : 128), e.clientX - dragOffset.current.x));
      const newY = Math.max(0, Math.min(window.innerHeight - (isMinimized ? 40 : 60), e.clientY - dragOffset.current.y));

      setPosition({ x: newX, y: newY });
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, isMinimized]);

  if (!isVisible) return (
    <button 
      onClick={() => setIsVisible(true)}
      className="fixed bottom-4 right-4 z-[100] w-10 h-10 bg-[#0a1a2f] border border-[#dcb06b] text-[#dcb06b] flex items-center justify-center clip-corner-sm hover:bg-[#dcb06b] hover:text-black transition-all shadow-[0_0_10px_rgba(220,176,107,0.3)]"
    >
      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
    </button>
  );

  return (
    <div 
      style={{ left: position.x, top: position.y }}
      className={`fixed z-[100] transition-shadow duration-300 ${isDragging ? 'shadow-[0_0_20px_rgba(220,176,107,0.5)]' : 'shadow-xl'}`}
    >
      {isMinimized ? (
        <button 
          onClick={() => setIsMinimized(false)}
          className="w-10 h-10 bg-[#0a1a2f]/90 backdrop-blur-md border border-[#dcb06b] text-[#dcb06b] flex items-center justify-center clip-corner-sm hover:scale-110 transition-transform"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
        </button>
      ) : (
        <div className="w-32 bg-[#0a1a2f]/90 backdrop-blur-md border border-[#dcb06b]/50 clip-corner-sm flex flex-col overflow-hidden shadow-2xl">
          {/* Draggable Header */}
          <div 
            onMouseDown={handleMouseDown}
            className={`h-5 bg-[#dcb06b]/20 flex items-center justify-between px-2 cursor-move select-none border-b border-[#dcb06b]/30 ${isDragging ? 'bg-[#dcb06b]/40' : ''}`}
          >
            <div className="flex gap-1 items-center">
               <div className="w-1 h-1 bg-[#dcb06b] rounded-full animate-pulse"></div>
               <span className="text-[7px] font-orbitron font-bold text-[#dcb06b] tracking-tighter">LOCAL SYSTEM</span>
            </div>
            <div className="flex gap-1">
              <button onClick={() => setIsMinimized(true)} className="text-[#dcb06b] hover:text-white">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" /></svg>
              </button>
              <button onClick={() => setIsVisible(false)} className="text-[#dcb06b] hover:text-red-500">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
          </div>

          {/* Time Display */}
          <div className="p-2 flex flex-col items-center">
             <div className="text-lg font-orbitron font-black text-white tracking-widest drop-shadow-[0_0_5px_rgba(255,255,255,0.3)]">
                {time}
             </div>
             <div className="text-[6px] font-orbitron text-[#dcb06b] uppercase tracking-[0.2em] mt-0.5 opacity-60">
                LOCAL TIME
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

