          />

          {/* Core Tip Point */}
          <circle cx="2" cy="2" r="1.5" fill="white" className="animate-pulse" />
        </svg>

        {/* Click Feedback Pulse */}
        {isMouseDown && (
          <div className="absolute top-0 left-0 w-12 h-12 -translate-x-1/2 -translate-y-1/2 rounded-full border border-white/50 animate-[ping_0.4s_ease-out_forwards]" />
