                   <span className="relative z-10 font-cinzel font-black text-xl text-red-500 group-hover:text-white tracking-widest">
                      CRIMSON VICTORY
                   </span>
                </button>
             </div>
          </div>
       </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { MatchResult, Role } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';

interface EvaluationScreenProps {
  match: MatchResult;
  winner: 'azure' | 'crimson';
  onComplete: (mvpId?: string, ratings?: Record<string, number>) => void;
}

export const EvaluationScreen: React.FC<EvaluationScreenProps> = ({ match, winner, onComplete }) => {
  const [mvpId, setMvpId] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const timerRef = useRef<number | null>(null);

  const [ratings, setRatings] = useState<Record<string, number>>({});

  useEffect(() => {
    const loadingTimer = setTimeout(() => {
        setIsLoading(false);
    }, 2500);

    return () => {
       clearTimeout(loadingTimer);
       if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (!isLoading && !timerRef.current) {
        timerRef.current = window.setInterval(() => {
            setElapsedSeconds(prev => prev + 1);
        }, 1000);
    }
  }, [isLoading]);

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData("type", "mvp-token");
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); 
    e.dataTransfer.dropEffect = "move";
  };

  const handleDrop = (e: React.DragEvent, playerId: string) => {
     e.preventDefault();
     const type = e.dataTransfer.getData("type");
     if (type === "mvp-token") {
        setMvpId(playerId);
     }
  };

  const cycleRatingUp = (playerId: string) => {
      setRatings(prev => {
          const current = prev[playerId] || 0;
          let next = 0;
          // Behavior: 0 -> 1 -> 2 -> 0 (Cycling Up)
          // If was negative, jump to positive 1
          if (current < 0) next = 1;
          else if (current === 0) next = 1;
          else if (current === 1) next = 2;
          else next = 0;

          const newState = { ...prev, [playerId]: next };
          if (next === 0) delete newState[playerId];
          return newState;
      });
  };

  const cycleRatingDown = (playerId: string) => {
    setRatings(prev => {
        const current = prev[playerId] || 0;
        let next = 0;
        // Behavior: 0 -> -1 -> -2 -> 0 (Cycling Down)
        // If was positive, jump to negative -1
        if (current > 0) next = -1;
        else if (current === 0) next = -1;
        else if (current === -1) next = -2;
        else next = 0;

        const newState = { ...prev, [playerId]: next };
        if (next === 0) delete newState[playerId];
        return newState;
    });
  };

  const renderRatingButton = (playerId: string, direction: 'up' | 'down', currentRating: number) => {
      const isUp = direction === 'up';
      let isActive = false;
      let isDouble = false;

      if (isUp) {
          isActive = currentRating > 0;
          isDouble = currentRating === 2;
      } else {
          isActive = currentRating < 0;
          isDouble = currentRating === -2;
      }

      const colorClass = isUp 
          ? (isActive ? 'text-green-400' : 'text-gray-600') 
          : (isActive ? 'text-red-500' : 'text-gray-600');

      const glowClass = isActive 
          ? (isUp ? 'drop-shadow-[0_0_8px_#4ade80]' : 'drop-shadow-[0_0_8px_#ef4444]') 
          : '';

      return (
          <button 
              onClick={() => isUp ? cycleRatingUp(playerId) : cycleRatingDown(playerId)} 
              className={`p-1 rounded hover:bg-white/10 transition-all duration-200 ${colorClass} ${glowClass} flex flex-col items-center justify-center -space-y-1`}
          >
              {isUp ? (
                  <>
                      {isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
                  </>
              ) : (
                  <>
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
                      {isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
                  </>
              )}
          </button>
      );
  };

  if (isLoading) {
    return (
        <div className="fixed inset-0 z-[100] bg-[#05090f] flex flex-col items-center justify-center">
            <div className="w-16 h-16 border-4 border-[#1e3a5f] border-t-[#dcb06b] rounded-full animate-spin mb-6"></div>
            <h2 className="text-[#dcb06b] font-orbitron text-xl tracking-[0.2em] animate-pulse">CALCULATING BATTLE DATA</h2>
            <div className="w-64 h-1 bg-[#1e3a5f] mt-4 rounded overflow-hidden">
                <div className="h-full bg-[#dcb06b] animate-[loading-bar_2s_ease-in-out_infinite]"></div>
            </div>
        </div>
    );
  }

  const MVPToken = () => (
    <div 
      draggable 
      onDragStart={handleDragStart}
      className="cursor-grab active:cursor-grabbing hover:scale-110 transition-transform"
    >
       <div className="w-12 h-12 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_15px_#fbbf24] border-2 border-white animate-pulse">
           <span className="font-black italic text-[#05090f] text-xs">MVP</span>
       </div>
    </div>
  );

  const winningTeamSlots = winner === 'azure' ? match.azureTeam : match.crimsonTeam;
  const rolesToRender = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;

  const renderTeamColumn = (teamSlots: typeof winningTeamSlots, teamName: string, isWinner: boolean, teamColor: 'cyan' | 'red') => {
      const borderColor = teamColor === 'cyan' ? 'border-[#00d2ff]' : 'border-[#ef4444]';
      const bgColor = teamColor === 'cyan' ? 'bg-[#00d2ff]/10' : 'bg-[#ef4444]/10';
      const textColor = teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500';

      return (
        <div className={`flex-1 w-full border ${borderColor} ${bgColor} p-0 clip-corner-md transition-all`}>
            <div className={`p-4 bg-opacity-30 border-b border-white/10 flex justify-between items-center ${teamColor === 'cyan' ? 'bg-[#00d2ff]' : 'bg-[#ef4444]'}`}>
                <div className="flex items-center gap-2">
                    <div className={`w-1 h-6 ${teamColor === 'cyan' ? 'bg-cyan-500' : 'bg-red-500'}`}></div>
                    <h3 className={`${textColor} font-cinzel font-bold text-xl`}>{teamName}</h3>
                </div>
                {isWinner && <span className="text-[#dcb06b] font-bold uppercase tracking-widest text-xs border border-[#dcb06b] px-2 py-1 rounded">Victory</span>}
            </div>

            <div className="p-4 space-y-2">
                {rolesToRender.map(role => {
                    const slot = teamSlots.find(s => s.role === role);
                    if(!slot) return null;
                    const isMvp = slot.player.id === mvpId;
                    const rating = ratings[slot.player.id] || 0;
                    const isCoach = role === Role.COACH;

                    return (
                        <div 
                            key={role} 
                            onDragOver={match.isCoachMode && !isCoach ? handleDragOver : undefined}
                            onDrop={match.isCoachMode && !isCoach ? (e) => handleDrop(e, slot.player.id) : undefined}
                            className={`
                                flex items-center justify-between bg-[#0a1a2f]/50 p-3 rounded border relative overflow-hidden group transition-all
                                ${isMvp ? 'border-yellow-400 shadow-[0_0_15px_rgba(251,191,36,0.3)]' : isCoach ? 'border-white/20 bg-white/5' : 'border-white/5 hover:border-white/20'}
                            `}
                        >
                            <div className="flex items-center gap-4 relative z-10 flex-1 min-w-0">
                                <div className={`shrink-0 ${isCoach ? 'text-white' : (teamColor === 'cyan' ? 'text-cyan-500/50' : 'text-red-500/50')}`}>
                                    {RoleIcons[role]}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <div className={`text-lg font-orbitron truncate ${isMvp ? 'text-[#dcb06b]' : 'text-white'}`}>{slot.player.name}</div>
                                </div>
                            </div>

                            {/* Evaluation Section - Hidden if not Coach Mode */}
                            {match.isCoachMode && (
                              <div className="flex items-center gap-2 relative z-10 shrink-0">
                                  <div className="flex flex-col gap-1 mr-2 items-center">
                                      {renderRatingButton(slot.player.id, 'up', rating)}
                                      {renderRatingButton(slot.player.id, 'down', rating)}
                                  </div>

                                  {/* MVP slot for non-coach players */}
                                  {!isCoach && (
                                    <div className="w-10 h-10 flex items-center justify-center">
                                        {isMvp ? (
                                            <div className="w-8 h-8 bg-yellow-500 rounded-full flex items-center justify-center font-black text-black text-[10px] shadow-[0_0_12px_#fbbf24]">MVP</div>
                                        ) : (
                                            <div className="w-8 h-8 border border-dashed border-white/10 rounded-full opacity-20 group-hover:opacity-100 transition-opacity"></div>
                                        )}
                                    </div>
                                  )}
                              </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[#05090f] fixed inset-0 z-[50] flex flex-col items-center justify-center p-4">
       <div className="relative z-10 w-full max-w-6xl animate-slide-in h-full overflow-y-auto py-8">
          <div className="text-center mb-6">
             <h1 className="text-3xl font-cinzel font-black text-[#dcb06b] tracking-widest uppercase mb-1">Evaluation</h1>
             <div className="flex flex-col items-center">
                <span className="text-[#8a9db8] text-[10px] font-orbitron tracking-widest uppercase mb-1">Session Duration</span>
                <div className="text-2xl font-mono font-bold text-white bg-black/50 px-6 py-1 rounded border border-[#dcb06b]/20">
                  {formatTime(elapsedSeconds)}
                </div>
             </div>
          </div>

          {/* MVP Token selection - Only in Coach Mode */}
          {match.isCoachMode && (
            <div className="flex flex-col items-center mb-8">
               {!mvpId ? <MVPToken /> : <button onClick={() => setMvpId('')} className="text-xs text-red-400 underline uppercase tracking-widest">Reset MVP</button>}
               <p className="text-[10px] text-[#4a5f78] mt-2 uppercase tracking-widest">Drag MVP badge to a player</p>
            </div>
          )}

          <div className="flex flex-col md:flex-row gap-8 items-start justify-center">
             {renderTeamColumn(match.azureTeam, "AZURE GOLEM TEAM", winner === 'azure', 'cyan')}
             {renderTeamColumn(match.crimsonTeam, "CRIMSON GOLEM TEAM", winner === 'crimson', 'red')}
          </div>
          <div className="mt-12 flex justify-center pb-8">
             <Button onClick={() => onComplete(mvpId, ratings)} className="px-16 py-4 text-xl shadow-[0_0_20px_#dcb06b]">FINISH EVALUATION</Button>
          </div>
       </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { MatchResult, TeamSlot, Role, Player } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  initialMode: 'draft' | 'battle';
  onReset: () => void; 
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => void; 
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
  onStartBattle: () => void; 
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ 
  match, activePlayers, initialMode, 
  onReset, onCompleteMatch, onReroll, onStartBattle 
}) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);

  useEffect(() => {
     if (initialMode === 'battle') {
        setViewState('final');
     } else {
        setViewState('drafting');
     }
  }, [initialMode]);

  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const formatRoleLabelShort = (role: Role) => {
    switch(role) {
        case Role.CLASH: return "CLASH";
        case Role.JUNGLE: return "JUNGLE";
        case Role.MID: return "MID";
        case Role.FARM: return "FARM";
        case Role.ROAM: return "ROAM";
        case Role.COACH: return "COACH";
        default: return (role as string).toUpperCase();
    }
  };

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;

    const roleToReveal = displayRoles[nextIndex];

    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) {
      startWheel('azure', roleToReveal);
      return;
    }

    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) {
      startWheel('crimson', roleToReveal);
      return;
    }
  };

  const handleSkipAll = () => {
    const allCards = new Set<string>();
    displayRoles.forEach(r => {
      allCards.add(getCardId('azure', r));
      allCards.add(getCardId('crimson', r));
    });
    setRevealedCards(allCards);
    setCurrentRoleIndex(displayRoles.length - 1);
  };

  const handleAbort = () => {
    if (window.confirm("Are you sure you want to abort the current draft? All progress will be lost.")) {
      onReset();
    }
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    const revealedPlayerIds = new Set<string>();
    match.azureTeam.forEach(slot => { if (revealedCards.has(getCardId('azure', slot.role))) revealedPlayerIds.add(slot.player.id); });
    match.crimsonTeam.forEach(slot => { if (revealedCards.has(getCardId('crimson', slot.role))) revealedPlayerIds.add(slot.player.id); });

    const candidates = activePlayers
      .filter(p => {
          if (revealedPlayerIds.has(p.id)) return false;
          if (role === Role.COACH) return p.roles.includes(Role.COACH);
          return p.isAllRoles || p.roles.includes(role);
      });

    const candidateNames = candidates.map(p => p.name);

    if (candidates.length === 1) {
        const cardId = getCardId(team, role);
        setAutoFillFlash(cardId);
        setRevealedCards(prev => new Set(prev).add(cardId));
        if (team === 'crimson') {
            setCurrentRoleIndex(prev => prev + 1);
        }
        setTimeout(() => setAutoFillFlash(null), 1000);
        return;
    }

    if (!candidateNames.includes(winner.name)) {
        candidateNames.push(winner.name);
    }

    const randomDuration = Math.floor(Math.random() * (10000 - 5000 + 1)) + 5000;

    setWheelState({
      isOpen: true,
      type: 'draft',
      team,
      role,
      winnerName: winner.name,
      candidates: candidateNames,
      duration: randomDuration
    });
  };

  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));

    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) return p.roles.includes(Role.COACH);
       return p.isAllRoles || p.roles.includes(role);
    });

    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    if (candidates.length === 1) {
        onReroll(team, role, candidates[0]);
        return;
    }

    const randomDuration = Math.floor(Math.random() * (9000 - 4000 + 1)) + 4000; 

    setWheelState({
        isOpen: true,
        type: 'reroll',
        team,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'draft') {
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));
        if (team === 'crimson') setCurrentRoleIndex(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }
    setWheelState(null);
  };

  const handleWheelCancel = () => setWheelState(null);
  const handleInitializeBattle = () => setViewState('transition');
  const handleTransitionComplete = () => { onStartBattle(); setViewState('final'); };
  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) { setWinningTeam(winner); setViewState('celebration'); } 
    else { onCompleteMatch(null); }
  };
  const handleCelebrationDismiss = () => setViewState('evaluation');
  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => { onCompleteMatch(winningTeam, mvpId, ratings); }

  if (viewState === 'evaluation' && winningTeam) return <EvaluationScreen match={match} winner={winningTeam} onComplete={handleEvaluationComplete} />;
  if (viewState === 'celebration' && winningTeam) return <VictoryCelebration winner={winningTeam} teamSlots={winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam} onDismiss={handleCelebrationDismiss} />;
  if (viewState === 'transition') return <PortalTransition azureTeam={match.azureTeam} crimsonTeam={match.crimsonTeam} onComplete={handleTransitionComplete} />;
  if (viewState === 'final') return <MatchSummary match={match} onReset={handleMatchDecided} />;

  const renderPlayerCard = (role: Role, roleIndex: number, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;
    const cardId = getCardId(team, role);
    const isRevealed = revealedCards.has(cardId);
    const isAutoFilled = autoFillFlash === cardId;
    const isCoach = role === Role.COACH;

    let theme = isCoach ? { bg: 'bg-[#1a1a1a]', border: 'border-white', glow: 'shadow-[0_0_20px_rgba(255,255,255,0.8)]', text: 'text-white', gradient: 'from-white/20 to-transparent' }
      : team === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-hok-cyan', glow: 'shadow-[0_0_10px_#00d2ff]', text: 'text-hok-cyan', gradient: 'from-[#00d2ff]/20 to-transparent' }
      : { bg: 'bg-[#1a0505]', border: 'border-hok-red', glow: 'shadow-[0_0_10px_#ef4444]', text: 'text-hok-red', gradient: 'from-[#c02d2d]/20 to-transparent' };

    if (!isRevealed) {
       return (
         <div className="h-12 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-75 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    return (
      <div className={`relative h-12 w-full animate-slide-in perspective-container group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
        <div className={`
            absolute inset-0 clip-corner-md border-l-4 tilt-card
            ${theme.bg} ${theme.border} 
            ${isAutoFilled ? 'shadow-[0_0_30px_#dcb06b] border-[#dcb06b]' : theme.glow}
            shadow-[0_0_15px_rgba(0,0,0,0.5)]
            transition-all duration-300 hover:brightness-110
        `}>
           <div className={`flex flex-col h-full relative z-10 px-4 py-0 justify-center ${team === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-0 px-2 py-0 rounded-sm bg-black/40 border border-white/10 ${theme.text} transform transition-transform duration-500 w-auto inline-block scale-[0.7] origin-${team === 'crimson' ? 'right' : 'left'}`}>
                {RoleIcons[role]}
             </div>
             <span className={`block text-base md:text-lg font-bold text-white truncate font-orbitron drop-shadow-md w-full`}>
                {player?.name}
             </span>
             {isAutoFilled && (
                 <div className="absolute top-0 right-2 text-[6px] text-[#dcb06b] font-black uppercase tracking-tighter animate-pulse">Auto-Assigned</div>
             )}
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }}
             className={`absolute top-1 p-1 bg-black/50 hover:bg-[#dcb06b] rounded-full transition-colors group-hover:opacity-100 opacity-0 text-white hover:text-black z-50 border border-white/20 ${team === 'azure' ? 'right-2' : 'left-2'}`}
             title="Re-roll this specific slot"
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
           </button>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "START DRAFT";
  if (nextRoleName) {
     const nextTeam = !revealedCards.has(getCardId('azure', nextRoleName)) ? 'AZURE' : 'CRIMSON';
     const roleLabel = formatRoleLabelShort(nextRoleName);
     buttonText = `SELECT ${nextTeam} ${roleLabel}`;
  }

  return (
    <>
      {wheelState && wheelState.isOpen && (
        <SpinWheel 
          candidates={wheelState.candidates} 
          winnerName={wheelState.winnerName} 
          team={wheelState.team} 
          roleName={wheelState.role} 
          roomId={match.roomId} 
          duration={wheelState.duration}
          onComplete={handleWheelComplete} 
          onCancel={handleWheelCancel} 
        />
      )}
      <div className="w-full max-w-7xl mx-auto px-4 py-2 pb-24 relative min-h-screen flex flex-col justify-center">
        <div className="absolute top-4 left-4 right-4 z-40 flex justify-between">
           <Button variant="outline" size="sm" onClick={handleAbort} className="border-red-900/50 text-red-500 hover:bg-red-900/20 text-[10px] px-3 py-1">
              <span className="flex items-center gap-2"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 15l-3-3m0 0l3-3m-3 3h8M3 12a9 9 0 1118 0 9 9 0 01-18 0z" /></svg> ABORT</span>
           </Button>
           {!isFinished && <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-[10px] px-3 py-1">SKIP ALL</Button>}
        </div>

        {/* COMPACT ROOM ID DISPLAY */}
        <div className="flex flex-col items-center mb-4 mt-8">
           <div className="flex flex-col items-center gap-0">
              <span className="text-[#dcb06b] font-orbitron text-[8px] tracking-[0.4em] font-black uppercase drop-shadow-sm mb-0">ROOM ID</span>
              <div className="relative scale-75">
                 <div className="absolute -inset-4 bg-[#dcb06b] blur-[20px] opacity-20 animate-pulse pointer-events-none"></div>
                 <div className="relative bg-black/80 border-2 border-[#dcb06b] px-10 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.4)]">
                    <span className="text-2xl md:text-3xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b] animate-[chromatic_0.2s_infinite]">
                      {match.roomId}
                    </span>
                 </div>
              </div>
           </div>

           <div className="flex justify-between items-center w-full relative max-w-5xl mt-2">
              <div className="w-1/3 text-center"><h2 className="text-sm md:text-2xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-200 to-cyan-600">AZURE GOLEM</h2></div>
              <div className="w-1/3 flex justify-center"><div className="relative w-12 h-12 flex items-center justify-center"><span className="text-xl font-black italic text-[#dcb06b] z-10 animate-pulse-fast">VS</span></div></div>
              <div className="w-1/3 text-center"><h2 className="text-sm md:text-2xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-200 to-red-600">CRIMSON GOLEM</h2></div>
           </div>
        </div>

        <div className="relative space-y-1.5 md:space-y-2 max-w-5xl mx-auto w-full">
          {displayRoles.map((role, idx) => (
            <div key={role} className="grid grid-cols-2 gap-4 md:gap-12 items-center">
               <div className="order-1">{renderPlayerCard(role, idx, 'azure')}</div>
               <div className="order-2">{renderPlayerCard(role, idx, 'crimson')}</div>
            </div>
          ))}
        </div>

        <div className="fixed bottom-0 left-0 right-0 p-4 z-50 flex justify-center items-end bg-gradient-to-t from-[#05090f] via-[#05090f]/80 to-transparent h-24 pointer-events-none">
           <div className="pointer-events-auto">
              {!isFinished ? (
                 <button onClick={handleNext} className="group relative px-8 h-12 bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-sm hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_15px_rgba(220,176,107,0.2)]">
                   {buttonText}
                 </button>
              ) : (
                 <Button onClick={handleInitializeBattle} className="px-10 h-12 text-sm animate-pulse">INITIALIZE BATTLE</Button>
              )}
           </div>
        </div>
      </div>
    </>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { MatchResult, Role } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';

interface EvaluationScreenProps {
  match: MatchResult;
  winner: 'azure' | 'crimson';
  onComplete: (mvpId?: string, ratings?: Record<string, number>) => void;
}

export const EvaluationScreen: React.FC<EvaluationScreenProps> = ({ match, winner, onComplete }) => {
  const [mvpId, setMvpId] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const timerRef = useRef<number | null>(null);

  const [ratings, setRatings] = useState<Record<string, number>>({});

  useEffect(() => {
    const loadingTimer = setTimeout(() => {
        setIsLoading(false);
    }, 2500);

    return () => {
       clearTimeout(loadingTimer);
       if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (!isLoading && !timerRef.current) {
        timerRef.current = window.setInterval(() => {
            setElapsedSeconds(prev => prev + 1);
        }, 1000);
    }
  }, [isLoading]);

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData("type", "mvp-token");
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); 
    e.dataTransfer.dropEffect = "move";
  };

  const handleDrop = (e: React.DragEvent, playerId: string) => {
     e.preventDefault();
     const type = e.dataTransfer.getData("type");
     if (type === "mvp-token") {
        setMvpId(playerId);
     }
  };

  const cycleRatingUp = (playerId: string) => {
      setRatings(prev => {
          const current = prev[playerId] || 0;
          let next = 0;
          if (current < 0) next = 1;
          else if (current === 0) next = 1;
          else if (current === 1) next = 2;
          else next = 0;

          const newState = { ...prev, [playerId]: next };
          if (next === 0) delete newState[playerId];
          return newState;
      });
  };

  const cycleRatingDown = (playerId: string) => {
    setRatings(prev => {
        const current = prev[playerId] || 0;
        let next = 0;
        if (current > 0) next = -1;
        else if (current === 0) next = -1;
        else if (current === -1) next = -2;
        else next = 0;

        const newState = { ...prev, [playerId]: next };
        if (next === 0) delete newState[playerId];
        return newState;
    });
  };

  const renderRatingButton = (playerId: string, direction: 'up' | 'down', currentRating: number) => {
      const isUp = direction === 'up';
      let isActive = false;
      let isDouble = false;

      if (isUp) {
          isActive = currentRating > 0;
          isDouble = currentRating === 2;
      } else {
          isActive = currentRating < 0;
          isDouble = currentRating === -2;
      }

      const colorClass = isUp 
          ? (isActive ? 'text-green-400' : 'text-gray-600') 
          : (isActive ? 'text-red-500' : 'text-gray-600');

      const glowClass = isActive 
          ? (isUp ? 'drop-shadow-[0_0_8px_#4ade80]' : 'drop-shadow-[0_0_8px_#ef4444]') 
          : '';

      return (
          <button 
              onClick={() => isUp ? cycleRatingUp(playerId) : cycleRatingDown(playerId)} 
              className={`p-0.5 rounded hover:bg-white/10 transition-all duration-200 ${colorClass} ${glowClass} flex flex-col items-center justify-center -space-y-1`}
          >
              {isUp ? (
                  <>
                      {isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={6}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={6}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
                  </>
              ) : (
                  <>
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={6}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
                      {isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={6}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
                  </>
              )}
          </button>
      );
  };

  if (isLoading) {
    return (
        <div className="fixed inset-0 z-[100] bg-[#05090f] flex flex-col items-center justify-center">
            <div className="w-12 h-12 border-4 border-[#1e3a5f] border-t-[#dcb06b] rounded-full animate-spin mb-4"></div>
            <h2 className="text-[#dcb06b] font-orbitron text-lg tracking-[0.2em] animate-pulse">ANALYZING BATTLE...</h2>
        </div>
    );
  }

  const MVPToken = () => (
    <div 
      draggable 
      onDragStart={handleDragStart}
      className="cursor-grab active:cursor-grabbing hover:scale-110 transition-transform"
    >
       <div className="w-10 h-10 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_15px_#fbbf24] border-2 border-white animate-pulse">
           <span className="font-black italic text-[#05090f] text-[10px]">MVP</span>
       </div>
    </div>
  );

  const winningTeamSlots = winner === 'azure' ? match.azureTeam : match.crimsonTeam;
  const rolesToRender = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;

  const renderTeamColumn = (teamSlots: typeof winningTeamSlots, teamName: string, isWinner: boolean, teamColor: 'cyan' | 'red') => {
      const borderColor = teamColor === 'cyan' ? 'border-[#00d2ff]' : 'border-[#ef4444]';
      const bgColor = teamColor === 'cyan' ? 'bg-[#00d2ff]/10' : 'bg-[#ef4444]/10';
      const textColor = teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500';

      return (
        <div className={`flex-1 w-full border ${borderColor} ${bgColor} p-0 clip-corner-md transition-all h-full flex flex-col`}>
            <div className={`p-2 bg-opacity-30 border-b border-white/10 flex justify-between items-center ${teamColor === 'cyan' ? 'bg-[#00d2ff]' : 'bg-[#ef4444]'}`}>
                <div className="flex items-center gap-2">
                    <div className={`w-0.5 h-4 ${teamColor === 'cyan' ? 'bg-cyan-500' : 'bg-red-500'}`}></div>
                    <h3 className={`${textColor} font-cinzel font-bold text-base`}>{teamName.split(' ')[0]}</h3>
                </div>
                {isWinner && <span className="text-[#dcb06b] font-bold uppercase tracking-widest text-[8px] border border-[#dcb06b] px-1.5 py-0.5 rounded">Winner</span>}
            </div>

            <div className="p-2 space-y-1.5 flex-1">
                {rolesToRender.map(role => {
                    const slot = teamSlots.find(s => s.role === role);
                    if(!slot) return null;
                    const isMvp = slot.player.id === mvpId;
                    const rating = ratings[slot.player.id] || 0;
                    const isCoach = role === Role.COACH;

                    return (
                        <div 
                            key={role} 
                            onDragOver={match.isCoachMode && !isCoach ? handleDragOver : undefined}
                            onDrop={match.isCoachMode && !isCoach ? (e) => handleDrop(e, slot.player.id) : undefined}
                            className={`
                                flex items-center justify-between bg-[#0a1a2f]/50 p-2 rounded border relative overflow-hidden group transition-all h-[42px]
                                ${isMvp ? 'border-yellow-400 shadow-[0_0_10px_rgba(251,191,36,0.3)]' : isCoach ? 'border-white/20 bg-white/5' : 'border-white/5 hover:border-white/20'}
                            `}
                        >
                            <div className="flex items-center gap-2 relative z-10 flex-1 min-w-0">
                                <div className={`shrink-0 scale-[0.6] ${isCoach ? 'text-white' : (teamColor === 'cyan' ? 'text-cyan-500/50' : 'text-red-500/50')}`}>
                                    {RoleIcons[role]}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <div className={`text-sm font-orbitron truncate ${isMvp ? 'text-[#dcb06b]' : 'text-white'}`}>{slot.player.name}</div>
                                </div>
                            </div>

                            {match.isCoachMode && (
                              <div className="flex items-center gap-1.5 relative z-10 shrink-0 scale-90">
                                  <div className="flex flex-col gap-0.5 items-center">
                                      {renderRatingButton(slot.player.id, 'up', rating)}
                                      {renderRatingButton(slot.player.id, 'down', rating)}
                                  </div>

                                  {!isCoach && (
                                    <div className="w-8 h-8 flex items-center justify-center">
                                        {isMvp ? (
                                            <div className="w-7 h-7 bg-yellow-500 rounded-full flex items-center justify-center font-black text-black text-[8px] shadow-[0_0_8px_#fbbf24]">MVP</div>
                                        ) : (
                                            <div className="w-7 h-7 border border-dashed border-white/10 rounded-full opacity-10 group-hover:opacity-40 transition-opacity"></div>
                                        )}
                                    </div>
                                  )}
                              </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[#05090f] fixed inset-0 z-[50] flex flex-col items-center justify-center p-2 overflow-hidden">
       <div className="relative z-10 w-full max-w-5xl flex flex-col h-full py-4 animate-slide-in">
          <div className="text-center mb-4 flex justify-between items-center px-4">
             <div className="text-left">
                <h1 className="text-xl font-cinzel font-black text-[#dcb06b] tracking-widest uppercase">Evaluation</h1>
                <p className="text-[8px] text-[#4a5f78] uppercase tracking-widest">Rate performance & select MVP</p>
             </div>

             <div className="flex flex-col items-center">
                <span className="text-[#8a9db8] text-[8px] font-orbitron tracking-widest uppercase mb-0.5">Session Time</span>
                <div className="text-lg font-mono font-bold text-white bg-black/50 px-4 py-0.5 rounded border border-[#dcb06b]/20">
                  {formatTime(elapsedSeconds)}
                </div>
             </div>
          </div>

          {match.isCoachMode && (
            <div className="flex flex-col items-center mb-4 gap-1">
               {!mvpId ? <MVPToken /> : <button onClick={() => setMvpId('')} className="text-[8px] text-red-400 underline uppercase tracking-widest">Reset MVP</button>}
               <p className="text-[8px] text-[#4a5f78] uppercase tracking-widest">Drag MVP badge to slot</p>
            </div>
          )}

          <div className="flex flex-col md:flex-row gap-4 items-stretch justify-center flex-1 max-h-[60vh]">
             {renderTeamColumn(match.azureTeam, "AZURE GOLEM", winner === 'azure', 'cyan')}
             {renderTeamColumn(match.crimsonTeam, "CRIMSON GOLEM", winner === 'crimson', 'red')}
          </div>

          <div className="mt-6 flex justify-center">
             <Button onClick={() => onComplete(mvpId, ratings)} className="px-12 py-3 text-sm shadow-[0_0_20px_#dcb06b]">FINISH EVALUATION</Button>
          </div>
       </div>
    </div>
  );
};

