         {status === 'scrolling' ? (
             <div className="flex flex-col items-center animate-pulse">
                <div className="text-[#dcb06b] font-orbitron text-[10px] uppercase tracking-[0.6em] font-bold mb-2">SCANNING LOBBY...</div>
                <div className="w-48 h-[1px] bg-[#1e3a5f] relative overflow-hidden clip-corner-sm">
                    <div className="absolute inset-0 bg-[#dcb06b] animate-[loading-bar_1.5s_infinite]"></div>
                </div>
             </div>
         ) : (
             <div className="text-white font-orbitron text-[10px] uppercase tracking-[0.4em] animate-[bounce_0.6s_infinite] text-center font-bold">
                <span className="text-[#dcb06b] block text-[8px] mb-1">LOCK ACHIEVED</span>
                PLAYER CONFIRMED
             </div>
         )}
      </div>

      <style>{`
        @keyframes loading-bar { 0% { transform: translateX(-100%); } 100% { transform: translateX(100%); } }
        @keyframes chromatic {
          0% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
          25% { text-shadow: -2px 0 0 #ff0000, 2px 0 0 #0000ff; }
          50% { text-shadow: 2px -1px 0 #ff0000, -2px 1px 0 #0000ff; }
          75% { text-shadow: -2px 1px 0 #ff0000, 2px -1px 0 #0000ff; }
          100% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { MatchResult, TeamSlot, Role, Player } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  initialMode: 'draft' | 'battle';
  onReset: () => void; 
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => void; 
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
  onStartBattle: () => void; 
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ 
  match, activePlayers, initialMode, 
  onReset, onCompleteMatch, onReroll, onStartBattle 
}) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);

  useEffect(() => {
     if (initialMode === 'battle') {
        setViewState('final');
     } else {
        setViewState('drafting');
     }
  }, [initialMode]);

  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const formatRoleLabelShort = (role: Role) => {
    switch(role) {
        case Role.CLASH: return "CLASH";
        case Role.JUNGLE: return "JUNGLE";
        case Role.MID: return "MID";
        case Role.FARM: return "FARM";
        case Role.ROAM: return "ROAM";
        case Role.COACH: return "COACH";
        default: return (role as string).toUpperCase();
    }
  };

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;
    const roleToReveal = displayRoles[nextIndex];
    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) { startWheel('azure', roleToReveal); return; }
    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) { startWheel('crimson', roleToReveal); return; }
  };

  const handleSkipAll = () => {
    const allCards = new Set<string>();
    displayRoles.forEach(r => { allCards.add(getCardId('azure', r)); allCards.add(getCardId('crimson', r)); });
    setRevealedCards(allCards);
    setCurrentRoleIndex(displayRoles.length - 1);
  };

  const handleAbort = () => {
    if (window.confirm("Abort current draft?")) onReset();
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    const revealedPlayerIds = new Set<string>();
    match.azureTeam.forEach(slot => { if (revealedCards.has(getCardId('azure', slot.role))) revealedPlayerIds.add(slot.player.id); });
    match.crimsonTeam.forEach(slot => { if (revealedCards.has(getCardId('crimson', slot.role))) revealedPlayerIds.add(slot.player.id); });

    const candidates = activePlayers.filter(p => {
          if (revealedPlayerIds.has(p.id)) return false;
          if (role === Role.COACH) return p.roles.includes(Role.COACH);
          return p.isAllRoles || p.roles.includes(role);
      });

    const candidateNames = candidates.map(p => p.name);
    if (candidates.length === 1) {
        const cardId = getCardId(team, role);
        setAutoFillFlash(cardId);
        setRevealedCards(prev => new Set(prev).add(cardId));
        if (team === 'crimson') setCurrentRoleIndex(prev => prev + 1);
        setTimeout(() => setAutoFillFlash(null), 1000);
        return;
    }
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);
    const randomDuration = Math.floor(Math.random() * (10000 - 5000 + 1)) + 5000;
    setWheelState({ isOpen: true, type: 'draft', team, role, winnerName: winner.name, candidates: candidateNames, duration: randomDuration });
  };

  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));
    if (benchPlayers.length === 0) return;
    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) return p.roles.includes(Role.COACH);
       return p.isAllRoles || p.roles.includes(role);
    });
    if (candidates.length === 0) return;
    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);
    if (candidates.length === 1) { onReroll(team, role, candidates[0]); return; }
    const randomDuration = Math.floor(Math.random() * (9000 - 4000 + 1)) + 4000; 
    setWheelState({ isOpen: true, type: 'reroll', team, role, winnerName: newPlayer.name, winnerPlayer: newPlayer, candidates: candidateNames, duration: randomDuration });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'draft') {
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));
        if (team === 'crimson') setCurrentRoleIndex(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }
    setWheelState(null);
  };

  const handleWheelCancel = () => setWheelState(null);
  const handleInitializeBattle = () => setViewState('transition');
  const handleTransitionComplete = () => { onStartBattle(); setViewState('final'); };
  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) { setWinningTeam(winner); setViewState('celebration'); } 
    else { onCompleteMatch(null); }
  };
  const handleCelebrationDismiss = () => setViewState('evaluation');
  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => { onCompleteMatch(winningTeam, mvpId, ratings); }

  if (viewState === 'evaluation' && winningTeam) return <EvaluationScreen match={match} winner={winningTeam} onComplete={handleEvaluationComplete} />;
  if (viewState === 'celebration' && winningTeam) return <VictoryCelebration winner={winningTeam} teamSlots={winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam} onDismiss={handleCelebrationDismiss} />;
  if (viewState === 'transition') return <PortalTransition azureTeam={match.azureTeam} crimsonTeam={match.crimsonTeam} onComplete={handleTransitionComplete} />;
  if (viewState === 'final') return <MatchSummary match={match} onReset={handleMatchDecided} />;

  const renderPlayerCard = (role: Role, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;
    const cardId = getCardId(team, role);
    const isRevealed = revealedCards.has(cardId);
    const isAutoFilled = autoFillFlash === cardId;
    const isCoach = role === Role.COACH;

    let theme = isCoach ? { bg: 'bg-[#1a1a1a]', border: 'border-white', glow: 'shadow-[0_0_20px_rgba(255,255,255,0.6)]', text: 'text-white', gradient: 'from-white/20 to-transparent' }
      : team === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-hok-cyan', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-hok-cyan', gradient: 'from-[#00d2ff]/20 to-transparent' }
      : { bg: 'bg-[#1a0505]', border: 'border-hok-red', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-hok-red', gradient: 'from-[#c02d2d]/20 to-transparent' };

    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${isAutoFilled ? 'shadow-[0_0_30px_#dcb06b] border-[#dcb06b]' : theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${team === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${team === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {player?.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>
           <button onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }} className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${team === 'azure' ? 'right-4' : 'left-4'}`}><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "START DRAFT";
  if (nextRoleName) {
     const nextTeam = !revealedCards.has(getCardId('azure', nextRoleName)) ? 'AZURE' : 'CRIMSON';
     buttonText = `SELECT ${nextTeam} ${formatRoleLabelShort(nextRoleName)}`;
  }

  return (
    <>
      {wheelState && wheelState.isOpen && (
        <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={match.roomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={handleWheelCancel} />
      )}
      <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">

        {/* TOP CONTROLS */}
        <div className="absolute top-8 left-8 right-8 z-40 flex justify-between">
           <Button variant="outline" size="sm" onClick={handleAbort} className="border-red-900/60 text-red-500 hover:bg-red-900/20 text-xs px-6">
              ABORT DRAFT
           </Button>
           {!isFinished && <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">SKIP ALL</Button>}
        </div>

        {/* HEADER AREA */}
        <div className="flex flex-col items-center mb-8">
           {/* TEAM TITLES */}
           <div className="flex justify-between items-center w-full relative max-w-7xl mb-6">
              <div className="w-1/3 text-center"><h2 className="text-3xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-200 to-cyan-600 tracking-widest drop-shadow-[0_0_20px_rgba(6,182,212,0.4)]">AZURE GOLEM</h2></div>
              <div className="w-1/3 flex justify-center"><div className="relative w-20 h-20 flex items-center justify-center"><span className="text-4xl font-black italic text-[#dcb06b] z-10 drop-shadow-[0_0_20px_rgba(220,176,107,0.6)]">VS</span></div></div>
              <div className="w-1/3 text-center"><h2 className="text-3xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-200 to-red-600 tracking-widest drop-shadow-[0_0_20px_rgba(239,68,68,0.4)]">CRIMSON GOLEM</h2></div>
           </div>

           {/* ROOM ID */}
           <div className="flex flex-col items-center gap-0 scale-[1] origin-top">
              <span className="text-[#dcb06b] font-orbitron text-[14px] tracking-[0.5em] font-black uppercase mb-2 opacity-90">BATTLE ROOM ID</span>
              <div className="relative">
                 <div className="absolute -inset-4 bg-[#dcb06b] blur-[25px] opacity-30 pointer-events-none"></div>
                 <div className="relative bg-black/95 border-2 border-[#dcb06b] px-16 py-4 clip-corner-sm flex flex-col items-center shadow-[0_0_40px_rgba(220,176,107,0.5)]">
                    <span className="text-4xl font-orbitron font-black text-white tracking-[0.5em] drop-shadow-[0_0_15px_#dcb06b] animate-[chromatic_0.2s_infinite]">
                      {match.roomId}
                    </span>
                 </div>
              </div>
           </div>
        </div>

        {/* PLAYER GRID OPTIMIZED FOR 16:9 - MAXIMUM WIDTH */}
        <div className="relative space-y-4 max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
          {displayRoles.map((role) => (
            <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
               <div>{renderPlayerCard(role, 'azure')}</div>
               <div>{renderPlayerCard(role, 'crimson')}</div>
            </div>
          ))}
        </div>

        {/* BOTTOM ACTION AREA */}
        <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
           <div className="pointer-events-auto">
              {!isFinished ? (
                 <button onClick={handleNext} className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]">
                   {buttonText}
                 </button>
              ) : (
                 <Button onClick={handleInitializeBattle} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">INITIALIZE BATTLE</Button>
              )}
           </div>
        </div>
      </div>
    </>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { MatchResult, Role } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';

interface EvaluationScreenProps {
  match: MatchResult;
  winner: 'azure' | 'crimson';
  onComplete: (mvpId?: string, ratings?: Record<string, number>) => void;
}

export const EvaluationScreen: React.FC<EvaluationScreenProps> = ({ match, winner, onComplete }) => {
  const [mvpId, setMvpId] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const timerRef = useRef<number | null>(null);
  const [ratings, setRatings] = useState<Record<string, number>>({});

  useEffect(() => {
    const loadingTimer = setTimeout(() => setIsLoading(false), 2000);
    return () => {
       clearTimeout(loadingTimer);
       if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (!isLoading && !timerRef.current) {
        timerRef.current = window.setInterval(() => setElapsedSeconds(prev => prev + 1), 1000);
    }
  }, [isLoading]);

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData("type", "mvp-token");
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); e.dataTransfer.dropEffect = "move"; };
  const handleDrop = (e: React.DragEvent, playerId: string) => {
     e.preventDefault();
     if (e.dataTransfer.getData("type") === "mvp-token") setMvpId(playerId);
  };

  const cycleRatingUp = (playerId: string) => {
      setRatings(prev => {
          const current = prev[playerId] || 0;
          let next = (current < 0) ? 1 : (current === 0) ? 1 : (current === 1) ? 2 : 0;
          const newState = { ...prev, [playerId]: next };
          if (next === 0) delete newState[playerId];
          return newState;
      });
  };

  const cycleRatingDown = (playerId: string) => {
    setRatings(prev => {
        const current = prev[playerId] || 0;
        let next = (current > 0) ? -1 : (current === 0) ? -1 : (current === -1) ? -2 : 0;
        const newState = { ...prev, [playerId]: next };
        if (next === 0) delete newState[playerId];
        return newState;
    });
  };

  const renderRatingButton = (playerId: string, direction: 'up' | 'down', currentRating: number) => {
      const isUp = direction === 'up';
      const isActive = isUp ? currentRating > 0 : currentRating < 0;

      // FIX: Panah double hanya aktif jika nilai sesuai dengan arah tombol (2 untuk up, -2 untuk down)
      const isDouble = isUp ? currentRating === 2 : currentRating === -2;

      const colorClass = isUp ? (isActive ? 'text-green-400' : 'text-gray-600') : (isActive ? 'text-red-500' : 'text-gray-600');
      const glowClass = isActive ? (isUp ? 'drop-shadow-[0_0_10px_#4ade80]' : 'drop-shadow-[0_0_10px_#ef4444]') : '';

      return (
          <button onClick={() => isUp ? cycleRatingUp(playerId) : cycleRatingDown(playerId)} className={`p-1.5 hover:bg-white/10 transition-all ${colorClass} ${glowClass} flex flex-col items-center -space-y-1.5`}>
              {isUp ? (
                  <>{isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}<svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg></>
              ) : (
                  <><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>{isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}</>
              )}
          </button>
      );
  };

  if (isLoading) {
    return (
        <div className="fixed inset-0 z-[100] bg-[#05090f] flex flex-col items-center justify-center">
            <div className="w-16 h-16 border-4 border-[#1e3a5f] border-t-[#dcb06b] rounded-full animate-spin mb-6"></div>
            <h2 className="text-[#dcb06b] font-orbitron text-xl tracking-[0.3em] animate-pulse">ANALYZING BATTLE RESULTS...</h2>
        </div>
    );
  }

  const MVPToken = () => (
    <div draggable onDragStart={handleDragStart} className="cursor-grab active:cursor-grabbing hover:scale-110 transition-transform">
       <div className="w-12 h-12 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_15px_#fbbf24] border-2 border-white/50 animate-pulse">
           <span className="font-black italic text-[#05090f] text-xs">MVP</span>
       </div>
    </div>
  );

  const renderTeamColumn = (teamSlots: any[], teamName: string, isWinner: boolean, teamColor: 'cyan' | 'red') => {
      const borderColor = teamColor === 'cyan' ? 'border-[#00d2ff]' : 'border-[#ef4444]';
      const bgColor = teamColor === 'cyan' ? 'bg-[#00d2ff]/10' : 'bg-[#ef4444]/10';
      const textColor = teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500';
      const rolesToRender = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;

      return (
        <div className={`flex-1 w-full border-2 ${borderColor} ${bgColor} clip-corner-md flex flex-col h-full overflow-hidden shadow-[0_0_40px_rgba(0,0,0,0.6)]`}>
            <div className={`p-4 bg-opacity-30 border-b-2 border-white/10 flex justify-between items-center ${teamColor === 'cyan' ? 'bg-[#00d2ff]' : 'bg-[#ef4444]'}`}>
                <h3 className={`${textColor} font-cinzel font-black text-lg tracking-[0.15em] drop-shadow-lg`}>{teamName.split(' ')[0]} GOLEM</h3>
                {isWinner && <span className="text-[#dcb06b] font-black uppercase tracking-[0.2em] text-[10px] border-2 border-[#dcb06b] px-3 py-1 rounded bg-black/50 shadow-[0_0_10px_#dcb06b]">Victory</span>}
            </div>
            <div className="p-3 space-y-2.5 overflow-y-auto flex-1">
                {rolesToRender.map(role => {
                    const slot = teamSlots.find(s => s.role === role);
                    if(!slot) return null;
                    const isMvp = slot.player.id === mvpId;
                    const rating = ratings[slot.player.id] || 0;
                    const isCoach = role === Role.COACH;

                    return (
                        <div key={role} 
                             onDragOver={!isCoach ? handleDragOver : undefined} 
                             onDrop={!isCoach ? (e) => handleDrop(e, slot.player.id) : undefined} 
                             className={`flex items-center justify-between bg-[#0a1a2f]/80 p-3 rounded-md border-2 h-16 relative transition-all duration-300 ${isMvp ? 'border-yellow-400 shadow-[0_0_20px_rgba(251,191,36,0.4)]' : isCoach ? 'border-white/20 bg-white/5 opacity-90' : 'border-white/5'}`}>
                            <div className="flex items-center gap-4 min-w-0 flex-1">
                                <div className={`shrink-0 scale-[0.85] ${isCoach ? 'text-white' : (teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500')}`}>{RoleIcons[role]}</div>
                                <div className="min-w-0 flex-1">
                                    <div className={`text-base md:text-lg font-orbitron truncate font-bold ${isMvp ? 'text-[#dcb06b]' : 'text-white'}`}>{slot.player.name}</div>
                                </div>
                            </div>

                            {!isCoach ? (
                              <div className="flex items-center gap-3 shrink-0">
                                  <div className="flex flex-col gap-1">{renderRatingButton(slot.player.id, 'up', rating)}{renderRatingButton(slot.player.id, 'down', rating)}</div>
                                  <div className="w-10 h-10 flex items-center justify-center">
                                      {isMvp ? <div className="w-9 h-9 bg-yellow-500 rounded-full flex items-center justify-center font-black text-black text-[10px] shadow-[0_0_10px_gold] border border-white/30">MVP</div> : <div className="w-9 h-9 border-2 border-dashed border-white/10 rounded-full opacity-30"></div>}
                                  </div>
                              </div>
                            ) : (
                                <div className="px-3 py-1 border-2 border-white/10 text-[9px] text-white/50 font-black uppercase tracking-widest rounded bg-white/5">COACH</div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[#05090f] fixed inset-0 z-[50] flex flex-col items-center justify-center p-4 overflow-hidden">
       <div className="w-full max-w-6xl h-full flex flex-col py-6 animate-slide-in">
          <div className="text-center mb-5 flex justify-between items-center px-6">
             <div className="text-left">
                <h1 className="text-3xl font-cinzel font-black text-[#dcb06b] tracking-[0.2em] uppercase mb-1">EVALUATION SESSION</h1>
                <p className="text-[10px] text-[#4a5f78] uppercase tracking-[0.4em] font-black">RATE PLAYER PERFORMANCE & ASSIGN MATCH MVP</p>
             </div>
             <div className="flex flex-col items-center">
                <span className="text-[#8a9db8] text-[10px] font-orbitron tracking-widest uppercase mb-2">TIME SESSION</span>
                <div className="text-2xl font-mono font-bold text-white bg-black/70 px-8 py-1.5 rounded-md border-2 border-[#dcb06b]/30 shadow-[0_0_20px_rgba(220,176,107,0.2)]">{formatTime(elapsedSeconds)}</div>
             </div>
          </div>

          <div className="flex flex-col items-center mb-6 h-14">
             {!mvpId ? <MVPToken /> : <button onClick={() => setMvpId('')} className="text-[10px] text-red-400 border-2 border-red-500/30 px-6 py-2 uppercase font-black tracking-[0.2em] hover:bg-red-950/60 transition-all clip-corner-sm shadow-lg">RESET MVP SELECTION</button>}
          </div>

          <div className="flex flex-col md:flex-row gap-8 items-stretch justify-center flex-1 max-h-[68vh]">
             {renderTeamColumn(match.azureTeam, "AZURE", winner === 'azure', 'cyan')}
             {renderTeamColumn(match.crimsonTeam, "CRIMSON", winner === 'crimson', 'red')}
          </div>

          <div className="mt-8 flex justify-center pb-4">
             <Button onClick={() => onComplete(mvpId, ratings)} size="lg" className="px-20 py-5 text-sm shadow-[0_0_30px_rgba(220,176,107,0.3)]">FINISH BATTLE EVALUATION</Button>
          </div>
       </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { MatchResult, TeamSlot, Role, Player } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  initialMode: 'draft' | 'battle';
  onReset: () => void; 
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => void; 
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
  onStartBattle: () => void; 
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ 
  match, activePlayers, initialMode, 
  onReset, onCompleteMatch, onReroll, onStartBattle 
}) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);

  useEffect(() => {
     if (initialMode === 'battle') {
        setViewState('final');
     } else {
        setViewState('drafting');
     }
  }, [initialMode]);

  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const formatRoleLabelShort = (role: Role) => {
    switch(role) {
        case Role.CLASH: return "CLASH";
        case Role.JUNGLE: return "JUNGLE";
        case Role.MID: return "MID";
        case Role.FARM: return "FARM";
        case Role.ROAM: return "ROAM";
        case Role.COACH: return "COACH";
        default: return (role as string).toUpperCase();
    }
  };

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;
    const roleToReveal = displayRoles[nextIndex];
    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) { startWheel('azure', roleToReveal); return; }
    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) { startWheel('crimson', roleToReveal); return; }
  };

  const handleSkipAll = () => {
    const allCards = new Set<string>();
    displayRoles.forEach(r => { allCards.add(getCardId('azure', r)); allCards.add(getCardId('crimson', r)); });
    setRevealedCards(allCards);
    setCurrentRoleIndex(displayRoles.length - 1);
  };

  const handleAbort = () => {
    if (window.confirm("Abort current draft?")) onReset();
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    const revealedPlayerIds = new Set<string>();
    match.azureTeam.forEach(slot => { if (revealedCards.has(getCardId('azure', slot.role))) revealedPlayerIds.add(slot.player.id); });
    match.crimsonTeam.forEach(slot => { if (revealedCards.has(getCardId('crimson', slot.role))) revealedPlayerIds.add(slot.player.id); });

    const candidates = activePlayers.filter(p => {
          if (revealedPlayerIds.has(p.id)) return false;
          if (role === Role.COACH) return p.roles.includes(Role.COACH);
          return p.isAllRoles || p.roles.includes(role);
      });

    const candidateNames = candidates.map(p => p.name);
    if (candidates.length === 1) {
        const cardId = getCardId(team, role);
        setAutoFillFlash(cardId);
        setRevealedCards(prev => new Set(prev).add(cardId));
        if (team === 'crimson') setCurrentRoleIndex(prev => prev + 1);
        setTimeout(() => setAutoFillFlash(null), 1000);
        return;
    }
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);
    const randomDuration = Math.floor(Math.random() * (10000 - 5000 + 1)) + 5000;
    setWheelState({ isOpen: true, type: 'draft', team, role, winnerName: winner.name, candidates: candidateNames, duration: randomDuration });
  };

  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));
    if (benchPlayers.length === 0) return;
    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) return p.roles.includes(Role.COACH);
       return p.isAllRoles || p.roles.includes(role);
    });
    if (candidates.length === 0) return;
    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);
    if (candidates.length === 1) { onReroll(team, role, candidates[0]); return; }
    const randomDuration = Math.floor(Math.random() * (9000 - 4000 + 1)) + 4000; 
    setWheelState({ isOpen: true, type: 'reroll', team, role, winnerName: newPlayer.name, winnerPlayer: newPlayer, candidates: candidateNames, duration: randomDuration });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'draft') {
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));
        if (team === 'crimson') setCurrentRoleIndex(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }
    setWheelState(null);
  };

  const handleWheelCancel = () => setWheelState(null);
  const handleInitializeBattle = () => setViewState('transition');
  const handleTransitionComplete = () => { onStartBattle(); setViewState('final'); };
  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) { setWinningTeam(winner); setViewState('celebration'); } 
    else { onCompleteMatch(null); }
  };
  const handleCelebrationDismiss = () => setViewState('evaluation');
  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => { onCompleteMatch(winningTeam, mvpId, ratings); }

  if (viewState === 'evaluation' && winningTeam) return <EvaluationScreen match={match} winner={winningTeam} onComplete={handleEvaluationComplete} />;
  if (viewState === 'celebration' && winningTeam) return <VictoryCelebration winner={winningTeam} teamSlots={winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam} onDismiss={handleCelebrationDismiss} />;
  if (viewState === 'transition') return <PortalTransition azureTeam={match.azureTeam} crimsonTeam={match.crimsonTeam} onComplete={handleTransitionComplete} />;
  if (viewState === 'final') return <MatchSummary match={match} onReset={handleMatchDecided} />;

  const renderPlayerCard = (role: Role, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;
    const cardId = getCardId(team, role);
    const isRevealed = revealedCards.has(cardId);
    const isAutoFilled = autoFillFlash === cardId;
    const isCoach = role === Role.COACH;

    let theme = isCoach ? { bg: 'bg-[#1a1a1a]', border: 'border-white', glow: 'shadow-[0_0_20px_rgba(255,255,255,0.6)]', text: 'text-white', gradient: 'from-white/20 to-transparent' }
      : team === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-hok-cyan', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-hok-cyan', gradient: 'from-[#00d2ff]/20 to-transparent' }
      : { bg: 'bg-[#1a0505]', border: 'border-hok-red', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-hok-red', gradient: 'from-[#c02d2d]/20 to-transparent' };

    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${isAutoFilled ? 'shadow-[0_0_30px_#dcb06b] border-[#dcb06b]' : theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${team === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${team === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {player?.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>
           <button onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }} className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${team === 'azure' ? 'right-4' : 'left-4'}`}><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "START DRAFT";
  if (nextRoleName) {
     const nextTeam = !revealedCards.has(getCardId('azure', nextRoleName)) ? 'AZURE' : 'CRIMSON';
     buttonText = `SELECT ${nextTeam} ${formatRoleLabelShort(nextRoleName)}`;
  }

  return (
    <>
      {wheelState && wheelState.isOpen && (
        <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={match.roomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={handleWheelCancel} />
      )}
      <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">

        {/* TOP CONTROLS - Fixed at the top, clear of team names */}
        <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center">
           <Button variant="outline" size="sm" onClick={handleAbort} className="border-red-900/60 text-red-500 hover:bg-red-900/20 text-xs px-6 shadow-[0_0_15px_rgba(239,68,68,0.2)]">
              ABORT DRAFT
           </Button>

           {/* ROOM ID CENTERED IN TOP BAR */}
           <div className="flex flex-col items-center gap-0 scale-[0.85] origin-top">
              <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.5em] font-black uppercase mb-1 opacity-70">ROOM ID</span>
              <div className="relative">
                 <div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div>
                 <div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]">
                    <span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">
                      {match.roomId}
                    </span>
                 </div>
              </div>
           </div>

           {!isFinished && <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">SKIP ALL</Button>}
        </div>

        {/* PLAYER GRID OPTIMIZED FOR 16:9 - MAXIMUM WIDTH */}
        <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">

          {/* TEAM TITLES POSITIONED ABOVE GRID COLUMNS */}
          <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6">
              <div className="text-left">
                  <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]">
                    AZURE <span className="hidden md:inline">GOLEM</span>
                  </h2>
                  <div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div>
              </div>
              <div className="text-right">
                  <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]">
                    <span className="hidden md:inline">CRIMSON</span> GOLEM
                  </h2>
                  <div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div>
              </div>
          </div>

          {/* VS INDICATOR FLOATING BEHIND GRID */}
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20">
              <span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span>
          </div>

          {/* PLAYER CARDS */}
          <div className="space-y-4 relative z-10">
            {displayRoles.map((role) => (
              <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
                <div>{renderPlayerCard(role, 'azure')}</div>
                <div>{renderPlayerCard(role, 'crimson')}</div>
              </div>
            ))}
          </div>
        </div>

        {/* BOTTOM ACTION AREA */}
        <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
           <div className="pointer-events-auto">
              {!isFinished ? (
                 <button onClick={handleNext} className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]">
                   {buttonText}
                 </button>
              ) : (
                 <Button onClick={handleInitializeBattle} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">INITIALIZE BATTLE</Button>
              )}
           </div>
        </div>
      </div>
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { MatchResult, TeamSlot, Role, Player } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  initialMode: 'draft' | 'battle';
  onReset: () => void; 
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => void; 
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
  onStartBattle: () => void; 
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ 
  match, activePlayers, initialMode, 
  onReset, onCompleteMatch, onReroll, onStartBattle 
}) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);

  useEffect(() => {
     if (initialMode === 'battle') {
        setViewState('final');
     } else {
        setViewState('drafting');
     }
  }, [initialMode]);

  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const formatRoleLabelShort = (role: Role) => {
    switch(role) {
        case Role.CLASH: return "CLASH";
        case Role.JUNGLE: return "JUNGLE";
        case Role.MID: return "MID";
        case Role.FARM: return "FARM";
        case Role.ROAM: return "ROAM";
        case Role.COACH: return "COACH";
        default: return (role as string).toUpperCase();
    }
  };

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;
    const roleToReveal = displayRoles[nextIndex];
    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) { startWheel('azure', roleToReveal); return; }
    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) { startWheel('crimson', roleToReveal); return; }
  };

  const handleSkipAll = () => {
    if (window.confirm("Are you sure you want to skip the remaining draft reveals?")) {
      const allCards = new Set<string>();
      displayRoles.forEach(r => { 
        allCards.add(getCardId('azure', r)); 
        allCards.add(getCardId('crimson', r)); 
      });
      setRevealedCards(allCards);
      setCurrentRoleIndex(displayRoles.length - 1);
    }
  };

  const handleAbort = () => {
    if (window.confirm("Abort current draft?")) onReset();
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    const revealedPlayerIds = new Set<string>();
    match.azureTeam.forEach(slot => { if (revealedCards.has(getCardId('azure', slot.role))) revealedPlayerIds.add(slot.player.id); });
    match.crimsonTeam.forEach(slot => { if (revealedCards.has(getCardId('crimson', slot.role))) revealedPlayerIds.add(slot.player.id); });

    const candidates = activePlayers.filter(p => {
          if (revealedPlayerIds.has(p.id)) return false;
          if (role === Role.COACH) return p.roles.includes(Role.COACH);
          return p.isAllRoles || p.roles.includes(role);
      });

    const candidateNames = candidates.map(p => p.name);
    if (candidates.length === 1) {
        const cardId = getCardId(team, role);
        setAutoFillFlash(cardId);
        setRevealedCards(prev => new Set(prev).add(cardId));
        if (team === 'crimson') setCurrentRoleIndex(prev => prev + 1);
        setTimeout(() => setAutoFillFlash(null), 1000);
        return;
    }
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);
    const randomDuration = Math.floor(Math.random() * (10000 - 5000 + 1)) + 5000;
    setWheelState({ isOpen: true, type: 'draft', team, role, winnerName: winner.name, candidates: candidateNames, duration: randomDuration });
  };

  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));
    if (benchPlayers.length === 0) return;
    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) return p.roles.includes(Role.COACH);
       return p.isAllRoles || p.roles.includes(role);
    });
    if (candidates.length === 0) return;
    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);
    if (candidates.length === 1) { onReroll(team, role, candidates[0]); return; }
    const randomDuration = Math.floor(Math.random() * (9000 - 4000 + 1)) + 4000; 
    setWheelState({ isOpen: true, type: 'reroll', team, role, winnerName: newPlayer.name, winnerPlayer: newPlayer, candidates: candidateNames, duration: randomDuration });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'draft') {
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));
        if (team === 'crimson') setCurrentRoleIndex(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }
    setWheelState(null);
  };

  const handleWheelCancel = () => setWheelState(null);
  const handleInitializeBattle = () => setViewState('transition');
  const handleTransitionComplete = () => { onStartBattle(); setViewState('final'); };
  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) { setWinningTeam(winner); setViewState('celebration'); } 
    else { onCompleteMatch(null); }
  };
  const handleCelebrationDismiss = () => setViewState('evaluation');
  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => { onCompleteMatch(winningTeam, mvpId, ratings); }

  if (viewState === 'evaluation' && winningTeam) return <EvaluationScreen match={match} winner={winningTeam} onComplete={handleEvaluationComplete} />;
  if (viewState === 'celebration' && winningTeam) return <VictoryCelebration winner={winningTeam} teamSlots={winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam} onDismiss={handleCelebrationDismiss} />;
  if (viewState === 'transition') return <PortalTransition azureTeam={match.azureTeam} crimsonTeam={match.crimsonTeam} onComplete={handleTransitionComplete} />;
  if (viewState === 'final') return <MatchSummary match={match} onReset={handleMatchDecided} />;

  const renderPlayerCard = (role: Role, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;
    const cardId = getCardId(team, role);
    const isRevealed = revealedCards.has(cardId);
    const isAutoFilled = autoFillFlash === cardId;
    const isCoach = role === Role.COACH;

    let theme = isCoach ? { bg: 'bg-[#1a1a1a]', border: 'border-white', glow: 'shadow-[0_0_20px_rgba(255,255,255,0.6)]', text: 'text-white', gradient: 'from-white/20 to-transparent' }
      : team === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-hok-cyan', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-hok-cyan', gradient: 'from-[#00d2ff]/20 to-transparent' }
      : { bg: 'bg-[#1a0505]', border: 'border-hok-red', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-hok-red', gradient: 'from-[#c02d2d]/20 to-transparent' };

    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${isAutoFilled ? 'shadow-[0_0_30px_#dcb06b] border-[#dcb06b]' : theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${team === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${team === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {player?.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>
           <button onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }} className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${team === 'azure' ? 'right-4' : 'left-4'}`}><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "START DRAFT";
  if (nextRoleName) {
     const nextTeam = !revealedCards.has(getCardId('azure', nextRoleName)) ? 'AZURE' : 'CRIMSON';
     buttonText = `SELECT ${nextTeam} ${formatRoleLabelShort(nextRoleName)}`;
  }

  return (
    <>
      {wheelState && wheelState.isOpen && (
        <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={match.roomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={handleWheelCancel} />
      )}
      <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">

        {/* TOP CONTROLS */}
        <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center">
           <Button variant="outline" size="sm" onClick={handleAbort} className="border-red-900/60 text-red-500 hover:bg-red-900/20 text-xs px-6 shadow-[0_0_15px_rgba(239,68,68,0.2)]">
              ABORT DRAFT
           </Button>

           {/* ROOM ID CENTERED IN TOP BAR */}
           <div className="flex flex-col items-center gap-0 scale-[0.85] origin-top">
              <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.5em] font-black uppercase mb-1 opacity-70">ROOM ID</span>
              <div className="relative">
                 <div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div>
                 <div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]">
                    <span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">
                      {match.roomId}
                    </span>
                 </div>
              </div>
           </div>

           {!isFinished && <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">SKIP ALL</Button>}
        </div>

        {/* PLAYER GRID AREA */}
        <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">

          {/* TEAM TITLES POSITIONED ABOVE GRID COLUMNS (MIRRORING) */}
          <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6">
              <div className="text-left">
                  <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]">
                    AZURE <span className="hidden md:inline">GOLEM</span>
                  </h2>
                  <div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div>
              </div>
              <div className="text-right">
                  <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]">
                    <span className="hidden md:inline">CRIMSON</span> GOLEM
                  </h2>
                  <div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div>
              </div>
          </div>

          {/* VS INDICATOR FLOATING BEHIND GRID */}
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20">
              <span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span>
          </div>

          {/* PLAYER CARDS */}
          <div className="space-y-4 relative z-10">
            {displayRoles.map((role) => (
              <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
                <div>{renderPlayerCard(role, 'azure')}</div>
                <div>{renderPlayerCard(role, 'crimson')}</div>
              </div>
            ))}
          </div>
        </div>

        {/* BOTTOM ACTION AREA */}
        <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
           <div className="pointer-events-auto">
              {!isFinished ? (
                 <button onClick={handleNext} className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]">
                   {buttonText}
                 </button>
              ) : (
                 <Button onClick={handleInitializeBattle} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">INITIALIZE BATTLE</Button>
              )}
           </div>
        </div>
      </div>
    </>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { MatchResult, Role } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';

interface EvaluationScreenProps {
  match: MatchResult;
  winner: 'azure' | 'crimson';
  onComplete: (mvpId?: string, ratings?: Record<string, number>) => void;
}

export const EvaluationScreen: React.FC<EvaluationScreenProps> = ({ match, winner, onComplete }) => {
  const [mvpId, setMvpId] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const timerRef = useRef<number | null>(null);
  const [ratings, setRatings] = useState<Record<string, number>>({});

  useEffect(() => {
    const loadingTimer = setTimeout(() => setIsLoading(false), 2000);
    return () => {
       clearTimeout(loadingTimer);
       if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (!isLoading && !timerRef.current) {
        timerRef.current = window.setInterval(() => setElapsedSeconds(prev => prev + 1), 1000);
    }
  }, [isLoading]);

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData("type", "mvp-token");
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); e.dataTransfer.dropEffect = "move"; };
  const handleDrop = (e: React.DragEvent, playerId: string) => {
     e.preventDefault();
     if (e.dataTransfer.getData("type") === "mvp-token") setMvpId(playerId);
  };

  const cycleRatingUp = (playerId: string) => {
      setRatings(prev => {
          const current = prev[playerId] || 0;
          let next = (current < 0) ? 1 : (current === 0) ? 1 : (current === 1) ? 2 : 0;
          const newState = { ...prev, [playerId]: next };
          if (next === 0) delete newState[playerId];
          return newState;
      });
  };

  const cycleRatingDown = (playerId: string) => {
    setRatings(prev => {
        const current = prev[playerId] || 0;
        let next = (current > 0) ? -1 : (current === 0) ? -1 : (current === -1) ? -2 : 0;
        const newState = { ...prev, [playerId]: next };
        if (next === 0) delete newState[playerId];
        return newState;
    });
  };

  const renderRatingButton = (playerId: string, direction: 'up' | 'down', currentRating: number) => {
      const isUp = direction === 'up';
      const isActive = isUp ? currentRating > 0 : currentRating < 0;

      // Panah double hanya aktif jika nilai sesuai dengan arah tombol (2 untuk up, -2 untuk down)
      const isDouble = isUp ? currentRating === 2 : currentRating === -2;

      const colorClass = isUp ? (isActive ? 'text-green-400' : 'text-gray-600') : (isActive ? 'text-red-500' : 'text-gray-600');
      const glowClass = isActive ? (isUp ? 'drop-shadow-[0_0_10px_#4ade80]' : 'drop-shadow-[0_0_10px_#ef4444]') : '';

      return (
          <button onClick={() => isUp ? cycleRatingUp(playerId) : cycleRatingDown(playerId)} className={`p-1.5 hover:bg-white/10 transition-all ${colorClass} ${glowClass} flex flex-col items-center -space-y-1.5`}>
              {isUp ? (
                  <>{isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}<svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg></>
              ) : (
                  <><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>{isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}</>
              )}
          </button>
      );
  };

  if (isLoading) {
    return (
        <div className="fixed inset-0 z-[100] bg-[#05090f] flex flex-col items-center justify-center">
            <div className="w-16 h-16 border-4 border-[#1e3a5f] border-t-[#dcb06b] rounded-full animate-spin mb-6"></div>
            <h2 className="text-[#dcb06b] font-orbitron text-xl tracking-[0.3em] animate-pulse">ANALYZING BATTLE RESULTS...</h2>
        </div>
    );
  }

  const MVPToken = () => (
    <div draggable onDragStart={handleDragStart} className="cursor-grab active:cursor-grabbing hover:scale-110 transition-transform">
       <div className="w-12 h-12 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_15px_#fbbf24] border-2 border-white/50 animate-pulse">
           <span className="font-black italic text-[#05090f] text-xs">MVP</span>
       </div>
    </div>
  );

  const renderTeamColumn = (teamSlots: any[], teamName: string, isWinner: boolean, teamColor: 'cyan' | 'red') => {
      const borderColor = teamColor === 'cyan' ? 'border-[#00d2ff]' : 'border-[#ef4444]';
      const bgColor = teamColor === 'cyan' ? 'bg-[#00d2ff]/10' : 'bg-[#ef4444]/10';
      const textColor = teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500';
      const rolesToRender = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;

      return (
        <div className={`flex-1 w-full border-2 ${borderColor} ${bgColor} clip-corner-md flex flex-col h-full overflow-hidden shadow-[0_0_40px_rgba(0,0,0,0.6)]`}>
            <div className={`p-4 bg-opacity-30 border-b-2 border-white/10 flex justify-between items-center ${teamColor === 'cyan' ? 'bg-[#00d2ff]' : 'bg-[#ef4444]'}`}>
                <h3 className={`${textColor} font-cinzel font-black text-lg tracking-[0.15em] drop-shadow-lg`}>{teamName.split(' ')[0]} GOLEM</h3>
                {isWinner && <span className="text-[#dcb06b] font-black uppercase tracking-[0.2em] text-[10px] border-2 border-[#dcb06b] px-3 py-1 rounded bg-black/50 shadow-[0_0_10px_#dcb06b]">Victory</span>}
            </div>
            <div className="p-3 space-y-2.5 overflow-y-auto flex-1">
                {rolesToRender.map(role => {
                    const slot = teamSlots.find(s => s.role === role);
                    if(!slot) return null;
                    const isMvp = slot.player.id === mvpId;
                    const rating = ratings[slot.player.id] || 0;
                    const isCoach = role === Role.COACH;

                    return (
                        <div key={role} 
                             onDragOver={!isCoach ? handleDragOver : undefined} 
                             onDrop={!isCoach ? (e) => handleDrop(e, slot.player.id) : undefined} 
                             className={`flex items-center justify-between bg-[#0a1a2f]/80 p-3 rounded-md border-2 h-16 relative transition-all duration-300 ${isMvp ? 'border-yellow-400 shadow-[0_0_20px_rgba(251,191,36,0.4)]' : isCoach ? 'border-white/20 bg-white/5 opacity-90' : 'border-white/5'}`}>
                            <div className="flex items-center gap-4 min-w-0 flex-1">
                                <div className={`shrink-0 scale-[0.85] ${isCoach ? 'text-white' : (teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500')}`}>{RoleIcons[role]}</div>
                                <div className="min-w-0 flex-1">
                                    <div className={`text-base md:text-lg font-orbitron truncate font-bold ${isMvp ? 'text-[#dcb06b]' : 'text-white'}`}>{slot.player.name}</div>
                                </div>
                            </div>

                            {!isCoach ? (
                              <div className="flex items-center gap-3 shrink-0">
                                  <div className="flex flex-col gap-1">{renderRatingButton(slot.player.id, 'up', rating)}{renderRatingButton(slot.player.id, 'down', rating)}</div>
                                  <div className="w-10 h-10 flex items-center justify-center">
                                      {isMvp ? <div className="w-9 h-9 bg-yellow-500 rounded-full flex items-center justify-center font-black text-black text-[10px] shadow-[0_0_10px_gold] border border-white/30">MVP</div> : <div className="w-9 h-9 border-2 border-dashed border-white/10 rounded-full opacity-30"></div>}
                                  </div>
                              </div>
                            ) : (
                                <div className="px-3 py-1 border-2 border-white/10 text-[9px] text-white/50 font-black uppercase tracking-widest rounded bg-white/5">COACH</div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[#05090f] fixed inset-0 z-[50] flex flex-col items-center justify-center p-4 overflow-hidden">
       <div className="w-full max-w-6xl h-full flex flex-col py-6 animate-slide-in">
          <div className="text-center mb-5 flex justify-between items-center px-6">
             <div className="text-left">
                <h1 className="text-3xl font-cinzel font-black text-[#dcb06b] tracking-[0.2em] uppercase mb-1">EVALUATION SESSION</h1>
                <p className="text-[10px] text-[#4a5f78] uppercase tracking-[0.4em] font-black">RATE PLAYER PERFORMANCE & ASSIGN MATCH MVP</p>
             </div>
             <div className="flex flex-col items-center">
                <span className="text-[#8a9db8] text-[10px] font-orbitron tracking-widest uppercase mb-2">TIME SESSION</span>
                <div className="text-2xl font-mono font-bold text-white bg-black/70 px-8 py-1.5 rounded-md border-2 border-[#dcb06b]/30 shadow-[0_0_20px_rgba(220,176,107,0.2)]">{formatTime(elapsedSeconds)}</div>
             </div>
          </div>

          <div className="flex flex-col items-center mb-6 h-14">
             {!mvpId ? <MVPToken /> : <button onClick={() => setMvpId('')} className="text-[10px] text-red-400 border-2 border-red-500/30 px-6 py-2 uppercase font-black tracking-[0.2em] hover:bg-red-950/60 transition-all clip-corner-sm shadow-lg">RESET MVP SELECTION</button>}
          </div>

          <div className="flex flex-col md:flex-row gap-8 items-stretch justify-center flex-1 max-h-[68vh]">
             {renderTeamColumn(match.azureTeam, "AZURE", winner === 'azure', 'cyan')}
             {renderTeamColumn(match.crimsonTeam, "CRIMSON", winner === 'crimson', 'red')}
          </div>

          <div className="mt-8 flex justify-center pb-4">
             <Button onClick={() => onComplete(mvpId, ratings)} size="lg" className="px-20 py-5 text-sm shadow-[0_0_30px_rgba(220,176,107,0.3)]">FINISH BATTLE EVALUATION</Button>
          </div>
       </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';

interface SpinWheelProps {
  candidates: string[];
  winnerName: string;
  onComplete: () => void;
  onCancel: () => void;
  team: 'azure' | 'crimson';
  roleName: string;
  roomId: string;
  duration: number;
}

export const SpinWheel: React.FC<SpinWheelProps> = ({ candidates, winnerName, onComplete, onCancel, team, roleName, roomId, duration }) => {
  const [status, setStatus] = useState<'scrolling' | 'completed'>('scrolling');
  const [scrollPosition, setScrollPosition] = useState(0);
  const [showInterference, setShowInterference] = useState(true);
  const reelRef = useRef<HTMLDivElement>(null);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const ITEM_HEIGHT = 70; 
  const VISIBLE_ITEMS = 5; 
  const [winnerIndex] = useState(() => Math.floor(duration / 25) + Math.floor(Math.random() * 30 - 15)); 
  const [reelItems, setReelItems] = useState<string[]>([]);

  useEffect(() => {
    const interTimer = setTimeout(() => setShowInterference(false), 300);
    const targetY = calculateTargetPosition();
    const scrollTimer = setTimeout(() => setScrollPosition(targetY), 50);
    timerRef.current = setTimeout(() => {
       setStatus('completed');
       setTimeout(() => onComplete(), 1500);
    }, duration);
    return () => {
        clearTimeout(interTimer); clearTimeout(scrollTimer);
        if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [duration]);

  useEffect(() => {
    const items: string[] = [];
    const uniqueCandidates = Array.from(new Set(candidates)) as string[];
    if (uniqueCandidates.length <= 1) {
       for (let i = 0; i < winnerIndex + VISIBLE_ITEMS + 5; i++) items.push(winnerName);
    } else {
       let previousName = '';
       for (let i = 0; i < winnerIndex + VISIBLE_ITEMS + 5; i++) {
          if (i === winnerIndex) { items.push(winnerName); previousName = winnerName; }
          else {
            const pool = uniqueCandidates.filter(name => name !== previousName);
            const randomName = pool[Math.floor(Math.random() * pool.length)];
            items.push(randomName); previousName = randomName;
          }
       }
    }
    setReelItems(items);
  }, [candidates, winnerName, winnerIndex]);

  const calculateTargetPosition = () => {
    const containerHeight = ITEM_HEIGHT * VISIBLE_ITEMS;
    const centerOffset = (containerHeight / 2) - (ITEM_HEIGHT / 2);
    return -(winnerIndex * ITEM_HEIGHT) + centerOffset;
  };

  const themeColor = team === 'azure' ? '#00d2ff' : '#ef4444';

  return (
    <div className="fixed inset-0 z-[60] flex flex-col items-center justify-center bg-black/98 backdrop-blur-2xl animate-slide-in">

      {showInterference && (
          <div className="absolute inset-0 z-[70] bg-[#05090f] flex items-center justify-center">
              <div className="text-[#dcb06b] font-orbitron text-xs tracking-[1.2em] animate-pulse uppercase">Syncing Roster...</div>
          </div>
      )}

      {/* NAVIGATION CONTROLS */}
      <div className="absolute top-6 right-6 z-50 flex gap-4">
        {status === 'scrolling' && (
          <button 
            onClick={() => { if(timerRef.current) clearTimeout(timerRef.current); setStatus('completed'); setScrollPosition(calculateTargetPosition()); setTimeout(onComplete, 500); }} 
            className="px-4 py-2 bg-[#dcb06b]/10 border border-[#dcb06b]/50 text-[#dcb06b] font-orbitron font-bold text-[10px] uppercase tracking-widest hover:bg-[#dcb06b] hover:text-black transition-all clip-corner-sm"
          >
            Skip Sync
          </button>
        )}
        <button 
          onClick={onCancel} 
          className="w-10 h-10 rounded-full border border-[#1e3a5f] bg-[#05090f] text-[#4a5f78] hover:text-white flex items-center justify-center transition-all"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      {/* HEADER SECTION */}
      <div className="mb-8 text-center flex flex-col items-center max-w-full px-6">
        <h2 className="text-3xl md:text-5xl font-black font-orbitron text-white uppercase drop-shadow-[0_0_20px_rgba(255,255,255,0.3)] tracking-wider animate-pulse mb-4">
          <span style={{ color: themeColor }}>{team}</span> {roleName.replace(' Lane', '')}
        </h2>

        {/* ROOM ID HIGHLIGHT */}
        <div className="flex flex-col items-center gap-1 scale-[0.75] origin-top">
            <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1.5 opacity-80">ROOM ID</span>
            <div className="relative">
               <div className="absolute -inset-4 bg-[#dcb06b] blur-[25px] opacity-20 pointer-events-none"></div>
               <div className="relative bg-black/90 border border-[#dcb06b] px-12 py-3 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]">
                  <span className="text-2xl md:text-4xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b] animate-[chromatic_0.2s_infinite]">
                    {roomId}
                  </span>
               </div>
            </div>
        </div>
      </div>

      {/* THE REEL */}
      <div className="relative scale-100 md:scale-105">
         <div className="absolute -left-12 top-1/2 -translate-y-1/2 w-10 h-[2px] bg-red-500/50 animate-pulse"></div>
         <div className="absolute -right-12 top-1/2 -translate-y-1/2 w-10 h-[2px] bg-red-500/50 animate-pulse"></div>

         <div 
            className={`relative overflow-hidden bg-[#05090f] border-x-2 border-[#dcb06b]/30 shadow-[0_0_100px_rgba(0,0,0,0.8)] transition-all duration-700 ${status === 'completed' ? 'border-[#dcb06b] scale-105 shadow-[0_0_50px_rgba(220,176,107,0.2)]' : ''}`} 
            style={{ width: '400px', height: `${ITEM_HEIGHT * VISIBLE_ITEMS}px` }}
         >
            <div 
              ref={reelRef} 
              className="w-full flex flex-col items-center will-change-transform" 
              style={{ transform: `translateY(${scrollPosition}px)`, filter: 'none', transition: status === 'scrolling' ? `transform ${duration}ms cubic-bezier(0.15, 0, 0.01, 1)` : 'none' }}
            >
               {reelItems.map((name, index) => (
                  <div key={index} className={`flex items-center justify-center w-full font-orbitron font-bold uppercase tracking-widest transition-all duration-300 ${(index === winnerIndex && status === 'completed') ? 'text-[#dcb06b] text-3xl md:text-4xl drop-shadow-[0_0_20px_#dcb06b] scale-110' : 'text-[#f0f4f8] text-xl md:text-2xl opacity-20'}`} style={{ height: `${ITEM_HEIGHT}px` }}>
                     {name}
                  </div>
               ))}
            </div>

            <div className="absolute top-0 left-0 right-0 h-24 bg-gradient-to-b from-[#05090f] to-transparent z-10 pointer-events-none"></div>
            <div className="absolute bottom-0 left-0 right-0 h-24 bg-gradient-to-t from-[#05090f] to-transparent z-10 pointer-events-none"></div>

            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-[70px] z-20 flex items-center justify-between px-2 pointer-events-none">
               <div className={`h-full w-2 border-l-2 border-t-2 border-b-2 transition-all duration-500 ${status === 'completed' ? 'border-[#dcb06b] animate-pulse' : 'border-[#4a5f78]/30'}`}></div>
               <div className={`h-full w-2 border-r-2 border-t-2 border-b-2 transition-all duration-500 ${status === 'completed' ? 'border-[#dcb06b] animate-pulse' : 'border-[#4a5f78]/30'}`}></div>
            </div>
         </div>
      </div>

      {/* FOOTER STATUS */}
      <div className="mt-8 h-20 flex flex-col items-center justify-center">
         {status === 'scrolling' ? (
             <div className="flex flex-col items-center animate-pulse">
                <div className="text-[#dcb06b] font-orbitron text-[10px] uppercase tracking-[0.6em] font-bold mb-2">SCANNING LOBBY...</div>
                <div className="w-48 h-[1px] bg-[#1e3a5f] relative overflow-hidden clip-corner-sm">
                    <div className="absolute inset-0 bg-[#dcb06b] animate-[loading-bar_1.5s_infinite]"></div>
                </div>
             </div>
         ) : (
             <div className="text-white font-orbitron text-[10px] uppercase tracking-[0.4em] animate-[bounce_0.6s_infinite] text-center font-bold">
                <span className="text-[#dcb06b] block text-[8px] mb-1">LOCK ACHIEVED</span>
                PLAYER CONFIRMED
             </div>
         )}
      </div>

      <style>{`
        @keyframes loading-bar { 0% { transform: translateX(-100%); } 100% { transform: translateX(100%); } }
        @keyframes chromatic {
          0% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
          25% { text-shadow: -2px 0 0 #ff0000, 2px 0 0 #0000ff; }
          50% { text-shadow: 2px -1px 0 #ff0000, -2px 1px 0 #0000ff; }
          75% { text-shadow: -2px 1px 0 #ff0000, 2px -1px 0 #0000ff; }
          100% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
        }
      `}</style>
    </div>
  );
};

