  const getPlayer = (slots: TeamSlot[], role: Role) => slots.find(s => s.role === role)?.player;

  return (
    <div className="fixed inset-0 z-[60] bg-[#05090f] flex flex-col items-center p-8 overflow-y-auto">
       <div className="w-full max-w-7xl animate-slide-in py-10">
          <div className="text-center mb-12">
             <h1 className="text-5xl font-cinzel font-black text-white tracking-[0.2em] mb-4">BATTLE SUMMARY</h1>
             <div className="h-1 w-48 bg-[#dcb06b] mx-auto opacity-50"></div>
          </div>

          <div className={`grid gap-8 mb-20 ${match.isBracketMode ? 'grid-cols-1 md:grid-cols-2 xl:grid-cols-4' : 'grid-cols-1 lg:grid-cols-2'}`}>
             {(match.isBracketMode ? match.bracketTeams! : [{ name: 'azure', slots: match.azureTeam, color: '#00d2ff' }, { name: 'crimson', slots: match.crimsonTeam, color: '#ef4444' }]).map((team: any) => (
                <div key={team.name} className="bg-[#0a1a2f]/50 border-t-4 p-6 clip-corner-sm shadow-xl" style={{ borderColor: team.color }}>
                   <h2 className="text-xl font-cinzel font-black text-white mb-6 flex justify-between items-center">
                      {team.name.toUpperCase()}
                      <span className="text-[10px] bg-white/10 px-2 py-0.5 rounded text-white/50">LOBBY READY</span>
                   </h2>
                   <div className="space-y-3">
                      {ROLES_ORDER.map(role => {
                         const p = getPlayer(team.slots, role);
                         return (
                            <div key={role} className="flex items-center gap-3 bg-black/30 p-2 rounded border border-white/5">
                               <div className="shrink-0 scale-75 opacity-70" style={{ color: team.color }}>{RoleIcons[role]}</div>
                               <div className="text-white font-orbitron font-bold truncate">{p?.name}</div>
                            </div>
                         );
                      })}
                   </div>
                   <button onClick={() => onReset(team.name)} className="w-full mt-6 py-3 font-cinzel font-black text-xs border-2 hover:bg-white hover:text-black transition-all clip-corner-sm" style={{ borderColor: team.color, color: team.color }}>DECLARE VICTORY</button>
                </div>
             ))}
          </div>

          <div className="flex justify-center">
             <Button onClick={() => onReset(null)} variant="secondary" className="px-20 border-white/20 text-white/50">MATCH DRAW / ABORT</Button>
          </div>
       </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { MatchResult, TeamSlot, Role, Player, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  initialMode: 'draft' | 'battle';
  onReset: () => void; 
  onCompleteMatch: (winner: 'azure' | 'crimson' | string | null, mvpId?: string, ratings?: Record<string, number>) => void; 
  onReroll: (team: 'azure' | 'crimson' | string, role: Role, newPlayer: Player) => void;
  onStartBattle: () => void; 
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ 
  match, activePlayers, initialMode, 
  onReset, onCompleteMatch, onReroll, onStartBattle 
}) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | string | null>(null);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);
  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);
  const [wheelState, setWheelState] = useState<any>(null);

  useEffect(() => {
     setViewState(initialMode === 'battle' ? 'final' : 'drafting');
  }, [initialMode]);

  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;
  const getCardId = (team: string, role: Role) => `${team}-${role}`;

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;
    const roleToReveal = displayRoles[nextIndex];

    const teamsToProcess = match.isBracketMode ? match.bracketTeams!.map(t => t.name) : ['azure', 'crimson'];

    for (const teamName of teamsToProcess) {
       const cid = getCardId(teamName, roleToReveal);
       if (!revealedCards.has(cid)) {
          startWheel(teamName, roleToReveal);
          return;
       }
    }
  };

  const startWheel = (teamName: string, role: Role) => {
    const teamColor = match.isBracketMode 
        ? match.bracketTeams?.find(t => t.name === teamName)?.color || '#ffffff'
        : (teamName === 'azure' ? '#00d2ff' : '#ef4444');

    const getSlots = () => {
        if (match.isBracketMode) return match.bracketTeams?.find(t => t.name === teamName)?.slots || [];
        return teamName === 'azure' ? match.azureTeam : match.crimsonTeam;
    };

    const teamSlots = getSlots();
    const winner = teamSlots.find(s => s.role === role)?.player;
    if (!winner) return;

    const revealedPlayerIds = new Set<string>();
    const allTeamsToScan = match.isBracketMode 
        ? match.bracketTeams!.map(t => ({ id: t.name, slots: t.slots })) 
        : [{ id: 'azure', slots: match.azureTeam }, { id: 'crimson', slots: match.crimsonTeam }];

    allTeamsToScan.forEach(t => {
       t.slots.forEach(slot => {
          if (revealedCards.has(getCardId(t.id, slot.role))) revealedPlayerIds.add(slot.player.id);
       });
    });

    const candidates = activePlayers.filter(p => !revealedPlayerIds.has(p.id) && (role === Role.COACH ? p.roles.includes(Role.COACH) : (p.isAllRoles || p.roles.includes(role))));
    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);

    if (candidateNames.length <= 1) {
        const cid = getCardId(teamName, role);
        setAutoFillFlash(cid);
        const newRevealed = new Set(revealedCards).add(cid);
        setRevealedCards(newRevealed);
        checkRoleCompletion(teamName, newRevealed);
        setTimeout(() => setAutoFillFlash(null), 800);
        return;
    }

    setWheelState({ 
        isOpen: true, 
        type: 'draft', 
        team: teamName, 
        color: teamColor,
        roleName: role, // Fixed: passing roleName instead of role
        winnerName: winner.name, 
        candidates: candidateNames, 
        duration: 5000 + Math.random() * 3000 
    });
  };

  const checkRoleCompletion = (lastRevealedTeam: string, currentRevealedSet: Set<string>) => {
     const teams = match.isBracketMode ? match.bracketTeams!.map(t => t.name) : ['azure', 'crimson'];
     const roleToVerify = displayRoles[currentRoleIndex + 1];
     if (!roleToVerify) return;

     const isRoleFullyRevealed = teams.every(t => currentRevealedSet.has(getCardId(t, roleToVerify)));
     if (isRoleFullyRevealed) {
        setCurrentRoleIndex(prev => prev + 1);
     }
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'draft') {
        const newSet = new Set(revealedCards).add(getCardId(wheelState.team, wheelState.roleName));
        setRevealedCards(newSet);
        checkRoleCompletion(wheelState.team, newSet);
    } else if (wheelState.type === 'reroll') {
        onReroll(wheelState.team, wheelState.roleName, wheelState.winnerPlayer);
    }
    setWheelState(null);
  };

  const renderCard = (role: Role, teamName: string, color: string) => {
    const cardId = getCardId(teamName, role);
    const isRevealed = revealedCards.has(cardId);
    const isAutoFilled = autoFillFlash === cardId;
    const teamSlots = match.isBracketMode 
        ? match.bracketTeams?.find(t => t.name === teamName)?.slots 
        : (teamName === 'azure' ? match.azureTeam : match.crimsonTeam);
    const player = teamSlots?.find(s => s.role === role)?.player;

    if (!isRevealed) {
      return (
        <div className="h-16 w-full border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-30 clip-corner-sm group hover:opacity-50 transition-all">
           <div className="text-[#1e3a5f] transform scale-75 group-hover:text-white/20">{RoleIcons[role]}</div>
        </div>
      );
    }

    return (
      <div className={`relative h-16 w-full animate-slide-in group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
        <div className={`absolute inset-0 border-l-4 clip-corner-sm flex items-center px-4 bg-[#0a1a2f] shadow-lg transition-all`} style={{ borderColor: color }}>
           <div className="flex-1 min-w-0">
             <div className="text-[8px] uppercase font-black opacity-50 flex items-center gap-1" style={{ color }}>
                {RoleIcons[role]}
             </div>
             <div className="text-white font-orbitron font-bold text-lg truncate drop-shadow-sm">{player?.name}</div>
           </div>
        </div>
      </div>
    );
  };

  const isFinished = revealedCards.size === (match.isBracketMode ? match.bracketTeams!.length * 5 : (match.isCoachMode ? 12 : 10));

  return (
    <div className="min-h-screen bg-[#05090f] flex flex-col items-center justify-center p-4 relative overflow-hidden">
      {wheelState?.isOpen && <SpinWheel {...wheelState} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} roomId={match.roomId} />}

      <div className="absolute top-6 left-6 right-6 flex justify-between items-center z-50">
         <Button variant="outline" size="sm" onClick={onReset} className="text-red-500 border-red-900/40">ABORT</Button>
         <div className="bg-black/80 border border-[#dcb06b]/50 px-6 py-2 clip-corner-sm font-orbitron font-black text-white text-xl tracking-[0.3em] shadow-[0_0_15px_rgba(220,176,107,0.2)]">{match.roomId}</div>
         <Button variant="outline" size="sm" onClick={() => { 
           const all = new Set<string>();
           if (match.isBracketMode) match.bracketTeams!.forEach(t => displayRoles.forEach(r => all.add(getCardId(t.name, r))));
           else ['azure', 'crimson'].forEach(t => displayRoles.forEach(r => all.add(getCardId(t, r))));
           setRevealedCards(all);
           setCurrentRoleIndex(displayRoles.length - 1);
         }} className="text-[#dcb06b] border-[#dcb06b]/40">SKIP</Button>
      </div>

      <div className="w-full max-w-7xl flex-1 flex flex-col justify-center gap-8 py-20 px-6 overflow-y-auto">
        <div className={`grid gap-x-8 gap-y-12 items-start ${match.isBracketMode ? 'grid-cols-2 lg:grid-cols-4' : 'grid-cols-2'}`}>
           {(match.isBracketMode ? match.bracketTeams! : [{ name: 'azure', color: '#00d2ff', slots: match.azureTeam }, { name: 'crimson', color: '#ef4444', slots: match.crimsonTeam }]).map((team: any) => (
              <div key={team.name} className="space-y-4">
                 <div className="flex flex-col mb-4">
                    <h2 className="font-cinzel font-black text-2xl tracking-widest text-white drop-shadow-md">{team.name.toUpperCase()}</h2>
                    <div className="h-1 w-full mt-1 opacity-50" style={{ background: `linear-gradient(to right, ${team.color}, transparent)` }}></div>
                 </div>
                 {displayRoles.map(role => (
                    <div key={role}>{renderCard(role, team.name, team.color)}</div>
                 ))}
              </div>
           ))}
        </div>
      </div>

      <div className="fixed bottom-8 z-50">
         {!isFinished ? (
            <Button onClick={handleNext} size="lg" className="px-16 h-16 shadow-[0_0_30px_rgba(220,176,107,0.4)]">NEXT REVEAL</Button>
         ) : (
            <Button onClick={onStartBattle} size="lg" className="px-20 h-16 bg-white text-black border-white animate-pulse">START BATTLE</Button>
         )}
      </div>

      {viewState === 'final' && <MatchSummary match={match} onReset={(winner) => { setWinningTeam(winner); setViewState('celebration'); }} />}
      {viewState === 'celebration' && winningTeam && <VictoryCelebration winner={winningTeam as any} teamSlots={match.isBracketMode ? match.bracketTeams!.find(t => t.name === winningTeam)!.slots : (winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam)} onDismiss={() => setViewState('evaluation')} />}
      {viewState === 'evaluation' && winningTeam && <EvaluationScreen match={match} winner={winningTeam as any} onComplete={onCompleteMatch} />}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';

interface SpinWheelProps {
  candidates: string[];
  winnerName: string;
  onComplete: () => void;
  onCancel: () => void;
  team: string;
  color?: string;
  roleName: string;
  roomId: string;
  duration: number;
}

export const SpinWheel: React.FC<SpinWheelProps> = ({ candidates, winnerName, onComplete, onCancel, team, color, roleName, roomId, duration }) => {
  const [status, setStatus] = useState<'scrolling' | 'completed'>('scrolling');
  const [scrollPosition, setScrollPosition] = useState(0);
  const [showInterference, setShowInterference] = useState(true);
  const reelRef = useRef<HTMLDivElement>(null);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const ITEM_HEIGHT = 70; 
  const VISIBLE_ITEMS = 5; 
  const [winnerIndex] = useState(() => Math.floor(duration / 25) + Math.floor(Math.random() * 30 - 15)); 
  const [reelItems, setReelItems] = useState<string[]>([]);

  useEffect(() => {
    const interTimer = setTimeout(() => setShowInterference(false), 300);
    const targetY = calculateTargetPosition();
    const scrollTimer = setTimeout(() => setScrollPosition(targetY), 50);
    timerRef.current = setTimeout(() => {
       setStatus('completed');
       setTimeout(() => onComplete(), 1500);
    }, duration);
    return () => {
        clearTimeout(interTimer); clearTimeout(scrollTimer);
        if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [duration]);

  useEffect(() => {
    const items: string[] = [];
    const uniqueCandidates = Array.from(new Set(candidates)) as string[];
    if (uniqueCandidates.length <= 1) {
       for (let i = 0; i < winnerIndex + VISIBLE_ITEMS + 5; i++) items.push(winnerName);
    } else {
       let previousName = '';
       for (let i = 0; i < winnerIndex + VISIBLE_ITEMS + 5; i++) {
          if (i === winnerIndex) { items.push(winnerName); previousName = winnerName; }
          else {
            const pool = uniqueCandidates.filter(name => name !== previousName);
            const randomName = pool[Math.floor(Math.random() * pool.length)];
            items.push(randomName); previousName = randomName;
          }
       }
    }
    setReelItems(items);
  }, [candidates, winnerName, winnerIndex]);

  const calculateTargetPosition = () => {
    const containerHeight = ITEM_HEIGHT * VISIBLE_ITEMS;
    const centerOffset = (containerHeight / 2) - (ITEM_HEIGHT / 2);
    return -(winnerIndex * ITEM_HEIGHT) + centerOffset;
  };

  const themeColor = color || (team === 'azure' ? '#00d2ff' : '#ef4444');
  const safeRoleName = (roleName || 'Selecting...').replace(' Lane', '');

  return (
    <div className="fixed inset-0 z-[60] flex flex-col items-center justify-center bg-black/98 backdrop-blur-2xl animate-slide-in">

      {showInterference && (
          <div className="absolute inset-0 z-[70] bg-[#05090f] flex items-center justify-center">
              <div className="text-[#dcb06b] font-orbitron text-xs tracking-[1.2em] animate-pulse uppercase">Syncing Roster...</div>
          </div>
      )}

      <div className="absolute top-6 right-6 z-50 flex gap-4">
        {status === 'scrolling' && (
          <button 
            onClick={() => { if(timerRef.current) clearTimeout(timerRef.current); setStatus('completed'); setScrollPosition(calculateTargetPosition()); setTimeout(onComplete, 500); }} 
            className="px-4 py-2 bg-[#dcb06b]/10 border border-[#dcb06b]/50 text-[#dcb06b] font-orbitron font-bold text-[10px] uppercase tracking-widest hover:bg-[#dcb06b] hover:text-black transition-all clip-corner-sm"
          >
            Skip Sync
          </button>
        )}
        <button 
          onClick={onCancel} 
          className="w-10 h-10 rounded-full border border-[#1e3a5f] bg-[#05090f] text-[#4a5f78] hover:text-white flex items-center justify-center transition-all"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      <div className="mb-8 text-center flex flex-col items-center max-w-full px-6">
        <h2 className="text-3xl md:text-5xl font-black font-orbitron text-white uppercase drop-shadow-[0_0_20px_rgba(255,255,255,0.3)] tracking-wider animate-pulse mb-4">
          <span style={{ color: themeColor }}>{team}</span> {safeRoleName}
        </h2>

        <div className="flex flex-col items-center gap-1 scale-[0.75] origin-top">
            <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1.5 opacity-80">ROOM ID</span>
            <div className="relative">
               <div className="absolute -inset-4 bg-[#dcb06b] blur-[25px] opacity-20 pointer-events-none"></div>
               <div className="relative bg-black/90 border border-[#dcb06b] px-12 py-3 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]">
                  <span className="text-2xl md:text-4xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b] animate-[chromatic_0.2s_infinite]">
                    {roomId}
                  </span>
               </div>
            </div>
        </div>
      </div>

      <div className="relative scale-100 md:scale-105">
         <div className="absolute -left-12 top-1/2 -translate-y-1/2 w-10 h-[2px] bg-red-500/50 animate-pulse"></div>
         <div className="absolute -right-12 top-1/2 -translate-y-1/2 w-10 h-[2px] bg-red-500/50 animate-pulse"></div>

         <div 
            className={`relative overflow-hidden bg-[#05090f] border-x-2 border-[#dcb06b]/30 shadow-[0_0_100px_rgba(0,0,0,0.8)] transition-all duration-700 ${status === 'completed' ? 'border-[#dcb06b] scale-105 shadow-[0_0_50px_rgba(220,176,107,0.2)]' : ''}`} 
            style={{ width: '400px', height: `${ITEM_HEIGHT * VISIBLE_ITEMS}px` }}
         >
            <div 
              ref={reelRef} 
              className="w-full flex flex-col items-center will-change-transform" 
              style={{ transform: `translateY(${scrollPosition}px)`, transition: status === 'scrolling' ? `transform ${duration}ms cubic-bezier(0.15, 0, 0.01, 1)` : 'none' }}
            >
               {reelItems.map((name, index) => (
                  <div key={index} className={`flex items-center justify-center w-full font-orbitron font-bold uppercase tracking-widest transition-all duration-300 ${(index === winnerIndex && status === 'completed') ? 'text-[#dcb06b] text-3xl md:text-4xl drop-shadow-[0_0_20px_#dcb06b] scale-110' : 'text-[#f0f4f8] text-xl md:text-2xl opacity-20'}`} style={{ height: `${ITEM_HEIGHT}px` }}>
                     {name}
                  </div>
               ))}
            </div>

            <div className="absolute top-0 left-0 right-0 h-24 bg-gradient-to-b from-[#05090f] to-transparent z-10 pointer-events-none"></div>
            <div className="absolute bottom-0 left-0 right-0 h-24 bg-gradient-to-t from-[#05090f] to-transparent z-10 pointer-events-none"></div>

            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-[70px] z-20 flex items-center justify-between px-2 pointer-events-none">
               <div className={`h-full w-2 border-l-2 border-t-2 border-b-2 transition-all duration-500 ${status === 'completed' ? 'border-[#dcb06b] animate-pulse' : 'border-[#4a5f78]/30'}`}></div>
               <div className={`h-full w-2 border-r-2 border-t-2 border-b-2 transition-all duration-500 ${status === 'completed' ? 'border-[#dcb06b] animate-pulse' : 'border-[#4a5f78]/30'}`}></div>
            </div>
         </div>
      </div>

      <div className="mt-8 h-20 flex flex-col items-center justify-center">
         {status === 'scrolling' ? (
             <div className="flex flex-col items-center animate-pulse">
                <div className="text-[#dcb06b] font-orbitron text-[10px] uppercase tracking-[0.6em] font-bold mb-2">SCANNING LOBBY...</div>
                <div className="w-48 h-[1px] bg-[#1e3a5f] relative overflow-hidden clip-corner-sm">
                    <div className="absolute inset-0 bg-[#dcb06b] animate-[loading-bar_1.5s_infinite]"></div>
                </div>
             </div>
         ) : (
             <div className="text-white font-orbitron text-[10px] uppercase tracking-[0.4em] animate-[bounce_0.6s_infinite] text-center font-bold">
                <span className="text-[#dcb06b] block text-[8px] mb-1">LOCK ACHIEVED</span>
                PLAYER CONFIRMED
             </div>
         )}
      </div>

      <style>{`
        @keyframes loading-bar { 0% { transform: translateX(-100%); } 100% { transform: translateX(100%); } }
        @keyframes chromatic {
          0% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
          25% { text-shadow: -2px 0 0 #ff0000, 2px 0 0 #0000ff; }
          50% { text-shadow: 2px -1px 0 #ff0000, -2px 1px 0 #0000ff; }
          75% { text-shadow: -2px 1px 0 #ff0000, 2px -1px 0 #0000ff; }
          100% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { MatchResult, TeamSlot, Role, Player, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  initialMode: 'draft' | 'battle';
  onReset: () => void; 
  onCompleteMatch: (winner: 'azure' | 'crimson' | string | null, mvpId?: string, ratings?: Record<string, number>) => void; 
  onReroll: (team: 'azure' | 'crimson' | string, role: Role, newPlayer: Player) => void;
  onStartBattle: () => void; 
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ 
  match, activePlayers, initialMode, 
  onReset, onCompleteMatch, onReroll, onStartBattle 
}) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | string | null>(null);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);
  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);
  const [wheelState, setWheelState] = useState<any>(null);

  useEffect(() => {
     setViewState(initialMode === 'battle' ? 'final' : 'drafting');
  }, [initialMode]);

  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;
  const getCardId = (team: string, role: Role) => `${team}-${role}`;

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;
    const roleToReveal = displayRoles[nextIndex];

    const teamsToProcess = match.isBracketMode ? match.bracketTeams!.map(t => t.name) : ['azure', 'crimson'];

    for (const teamName of teamsToProcess) {
       const cid = getCardId(teamName, roleToReveal);
       if (!revealedCards.has(cid)) {
          startWheel(teamName, roleToReveal);
          return;
       }
    }
  };

  const startWheel = (teamName: string, role: Role) => {
    const teamColor = match.isBracketMode 
        ? match.bracketTeams?.find(t => t.name === teamName)?.color || '#ffffff'
        : (teamName === 'azure' ? '#00d2ff' : '#ef4444');

    const getSlots = () => {
        if (match.isBracketMode) return match.bracketTeams?.find(t => t.name === teamName)?.slots || [];
        return teamName === 'azure' ? match.azureTeam : match.crimsonTeam;
    };

    const teamSlots = getSlots();
    const winner = teamSlots.find(s => s.role === role)?.player;
    if (!winner) return;

    const revealedPlayerIds = new Set<string>();
    const allTeamsToScan = match.isBracketMode 
        ? match.bracketTeams!.map(t => ({ id: t.name, slots: t.slots })) 
        : [{ id: 'azure', slots: match.azureTeam }, { id: 'crimson', slots: match.crimsonTeam }];

    allTeamsToScan.forEach(t => {
       t.slots.forEach(slot => {
          if (revealedCards.has(getCardId(t.id, slot.role))) revealedPlayerIds.add(slot.player.id);
       });
    });

    const candidates = activePlayers.filter(p => !revealedPlayerIds.has(p.id) && (role === Role.COACH ? p.roles.includes(Role.COACH) : (p.isAllRoles || p.roles.includes(role))));
    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);

    if (candidateNames.length <= 1) {
        const cid = getCardId(teamName, role);
        setAutoFillFlash(cid);
        // Explicitly set type to string to fix inference error on line 93 (identified as 92 in error report)
        const newRevealed = new Set<string>(revealedCards).add(cid);
        setRevealedCards(newRevealed);
        checkRoleCompletion(teamName, newRevealed);
        setTimeout(() => setAutoFillFlash(null), 800);
        return;
    }

    setWheelState({ 
        isOpen: true, 
        type: 'draft', 
        team: teamName, 
        color: teamColor,
        roleName: role, // Fixed: passing roleName instead of role
        winnerName: winner.name, 
        candidates: candidateNames, 
        duration: 5000 + Math.random() * 3000 
    });
  };

  const checkRoleCompletion = (lastRevealedTeam: string, currentRevealedSet: Set<string>) => {
     const teams = match.isBracketMode ? match.bracketTeams!.map(t => t.name) : ['azure', 'crimson'];
     const roleToVerify = displayRoles[currentRoleIndex + 1];
     if (!roleToVerify) return;

     const isRoleFullyRevealed = teams.every(t => currentRevealedSet.has(getCardId(t, roleToVerify)));
     if (isRoleFullyRevealed) {
        setCurrentRoleIndex(prev => prev + 1);
     }
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'draft') {
        // Explicitly set type to string to fix inference error on line 125
        const newSet = new Set<string>(revealedCards).add(getCardId(wheelState.team, wheelState.roleName));
        setRevealedCards(newSet);
        checkRoleCompletion(wheelState.team, newSet);
    } else if (wheelState.type === 'reroll') {
        onReroll(wheelState.team, wheelState.roleName, wheelState.winnerPlayer);
    }
    setWheelState(null);
  };

  const renderCard = (role: Role, teamName: string, color: string) => {
    const cardId = getCardId(teamName, role);
    const isRevealed = revealedCards.has(cardId);
    const isAutoFilled = autoFillFlash === cardId;
    const teamSlots = match.isBracketMode 
        ? match.bracketTeams?.find(t => t.name === teamName)?.slots 
        : (teamName === 'azure' ? match.azureTeam : match.crimsonTeam);
    const player = teamSlots?.find(s => s.role === role)?.player;

    if (!isRevealed) {
      return (
        <div className="h-16 w-full border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-30 clip-corner-sm group hover:opacity-50 transition-all">
           <div className="text-[#1e3a5f] transform scale-75 group-hover:text-white/20">{RoleIcons[role]}</div>
        </div>
      );
    }

    return (
      <div className={`relative h-16 w-full animate-slide-in group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
        <div className={`absolute inset-0 border-l-4 clip-corner-sm flex items-center px-4 bg-[#0a1a2f] shadow-lg transition-all`} style={{ borderColor: color }}>
           <div className="flex-1 min-w-0">
             <div className="text-[8px] uppercase font-black opacity-50 flex items-center gap-1" style={{ color }}>
                {RoleIcons[role]}
             </div>
             <div className="text-white font-orbitron font-bold text-lg truncate drop-shadow-sm">{player?.name}</div>
           </div>
        </div>
      </div>
    );
  };

  const isFinished = revealedCards.size === (match.isBracketMode ? match.bracketTeams!.length * 5 : (match.isCoachMode ? 12 : 10));

  return (
    <div className="min-h-screen bg-[#05090f] flex flex-col items-center justify-center p-4 relative overflow-hidden">
      {wheelState?.isOpen && <SpinWheel {...wheelState} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} roomId={match.roomId} />}

      <div className="absolute top-6 left-6 right-6 flex justify-between items-center z-50">
         <Button variant="outline" size="sm" onClick={onReset} className="text-red-500 border-red-900/40">ABORT</Button>
         <div className="bg-black/80 border border-[#dcb06b]/50 px-6 py-2 clip-corner-sm font-orbitron font-black text-white text-xl tracking-[0.3em] shadow-[0_0_15px_rgba(220,176,107,0.2)]">{match.roomId}</div>
         <Button variant="outline" size="sm" onClick={() => { 
           const all = new Set<string>();
           if (match.isBracketMode) match.bracketTeams!.forEach(t => displayRoles.forEach(r => all.add(getCardId(t.name, r))));
           else ['azure', 'crimson'].forEach(t => displayRoles.forEach(r => all.add(getCardId(t, r))));
           setRevealedCards(all);
           setCurrentRoleIndex(displayRoles.length - 1);
         }} className="text-[#dcb06b] border-[#dcb06b]/40">SKIP</Button>
      </div>

      <div className="w-full max-w-7xl flex-1 flex flex-col justify-center gap-8 py-20 px-6 overflow-y-auto">
        <div className={`grid gap-x-8 gap-y-12 items-start ${match.isBracketMode ? 'grid-cols-2 lg:grid-cols-4' : 'grid-cols-2'}`}>
           {(match.isBracketMode ? match.bracketTeams! : [{ name: 'azure', color: '#00d2ff', slots: match.azureTeam }, { name: 'crimson', color: '#ef4444', slots: match.crimsonTeam }]).map((team: any) => (
              <div key={team.name} className="space-y-4">
                 <div className="flex flex-col mb-4">
                    <h2 className="font-cinzel font-black text-2xl tracking-widest text-white drop-shadow-md">{team.name.toUpperCase()}</h2>
                    <div className="h-1 w-full mt-1 opacity-50" style={{ background: `linear-gradient(to right, ${team.color}, transparent)` }}></div>
                 </div>
                 {displayRoles.map(role => (
                    <div key={role}>{renderCard(role, team.name, team.color)}</div>
                 ))}
              </div>
           ))}
        </div>
      </div>

      <div className="fixed bottom-8 z-50">
         {!isFinished ? (
            <Button onClick={handleNext} size="lg" className="px-16 h-16 shadow-[0_0_30px_rgba(220,176,107,0.4)]">NEXT REVEAL</Button>
         ) : (
            <Button onClick={onStartBattle} size="lg" className="px-20 h-16 bg-white text-black border-white animate-pulse">START BATTLE</Button>
         )}
      </div>

      {viewState === 'final' && <MatchSummary match={match} onReset={(winner) => { setWinningTeam(winner); setViewState('celebration'); }} />}
      {viewState === 'celebration' && winningTeam && <VictoryCelebration winner={winningTeam as any} teamSlots={match.isBracketMode ? match.bracketTeams!.find(t => t.name === winningTeam)!.slots : (winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam)} onDismiss={() => setViewState('evaluation')} />}
      {viewState === 'evaluation' && winningTeam && <EvaluationScreen match={match} winner={winningTeam as any} onComplete={onCompleteMatch} />}
    </div>
  );
};

export enum Role {
  CLASH = 'Clash Lane',
  JUNGLE = 'Jungler',
  MID = 'Mid Lane',
  FARM = 'Farm Lane',
  ROAM = 'Roam',
  COACH = 'Coach',
}

export interface PlayerStats {
  matchesPlayed: number;
  wins: number;
  currentStreak: number;
  maxStreak: number;
}

export interface Player {
  id: string;
  name: string;
  roles: Role[]; 
  isAllRoles: boolean;
  isActive: boolean;
  isLastMatchMvp?: boolean;
  lastMatchRating?: number;
  stats: PlayerStats;
}

export interface TeamSlot {
  role: Role;
  player: Player;
}

export interface BracketTeam {
  id: string;
  name: string;
  slots: TeamSlot[];
  color: string;
}

export interface TournamentMatch {
  id: string;
  teamAId: string | null; // ID of BracketTeam or null if waiting for previous winner
  teamBId: string | null;
  winnerId: string | null;
  round: number; // 0: Quarters, 1: Semis, 2: Finals
  matchLabel: string;
  isDrafted: boolean;
}

export interface TournamentBracket {
  teams: BracketTeam[];
  matches: TournamentMatch[];
  currentMatchId: string | null;
}

export interface MatchResult {
  roomId: string;
  azureTeam: TeamSlot[];
  crimsonTeam: TeamSlot[];
  bracketTeams?: BracketTeam[];
  isCoachMode: boolean;
  isBracketMode: boolean;
  timestamp: number;
  tournamentMatchId?: string; // Links this result to a specific match in a bracket
}

export interface MatchHistoryEntry extends MatchResult {
  id: string;
  winningTeam: 'azure' | 'crimson' | string | null;
  mvpId?: string;
  ratings?: Record<string, number>;
}

import { Player, Role, TeamSlot, MatchResult, BracketTeam, TournamentMatch, TournamentBracket } from '../types';
import { ROLES_ORDER } from '../constants';

function shuffle<T>(array: T[]): T[] {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
}

const canPlay = (player: Player, role: Role): boolean => {
  if (role === Role.COACH) return player.roles.includes(Role.COACH);
  if (player.roles.includes(Role.COACH) && player.roles.length === 1 && !player.isAllRoles) return false;
  if (player.isAllRoles) return true;
  return player.roles.includes(role);
};

export const generateMatch = (players: Player[], roomId: string, isCoachMode: boolean): MatchResult | null => {
  const requiredPlayers = isCoachMode ? 12 : 10;
  if (players.length < requiredPlayers) return null;

  const neededRoles: { team: 'azure' | 'crimson', role: Role }[] = [];
  ROLES_ORDER.forEach(role => {
    neededRoles.push({ team: 'azure', role });
    neededRoles.push({ team: 'crimson', role });
  });

  if (isCoachMode) {
    neededRoles.push({ team: 'azure', role: Role.COACH });
    neededRoles.push({ team: 'crimson', role: Role.COACH });
  }

  const pool = shuffle(players);
  const assignments: Map<number, Player> = new Map();
  const usedPlayerIds = new Set<string>();

  const solve = (slotIndex: number): boolean => {
    if (slotIndex >= neededRoles.length) return true;
    const currentSlot = neededRoles[slotIndex];
    for (const player of pool) {
      if (!usedPlayerIds.has(player.id) && canPlay(player, currentSlot.role)) {
        assignments.set(slotIndex, player);
        usedPlayerIds.add(player.id);
        if (solve(slotIndex + 1)) return true;
        assignments.delete(slotIndex);
        usedPlayerIds.delete(player.id);
      }
    }
    return false;
  };

  if (solve(0)) {
    const azureTeam: TeamSlot[] = [];
    const crimsonTeam: TeamSlot[] = [];
    for (let i = 0; i < neededRoles.length; i++) {
        const slot = neededRoles[i];
        const player = assignments.get(i)!;
        if (slot.team === 'azure') azureTeam.push({ role: slot.role, player });
        else crimsonTeam.push({ role: slot.role, player });
    }
    const roleOrder = [...ROLES_ORDER, Role.COACH];
    const sorter = (a: TeamSlot, b: TeamSlot) => roleOrder.indexOf(a.role) - roleOrder.indexOf(b.role);
    azureTeam.sort(sorter);
    crimsonTeam.sort(sorter);

    return { roomId, azureTeam, crimsonTeam, isCoachMode, isBracketMode: false, timestamp: Date.now() };
  }
  return null;
};

const BRACKET_COLORS = ['#00d2ff', '#ef4444', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899', '#f97316', '#6366f1'];

export const initializeTournament = (players: Player[], roomId: string, teamCount: number): TournamentBracket | null => {
  const pool = shuffle(players);
  const bracketTeams: BracketTeam[] = [];

  // Create Teams and randomize rosters immediately for the entire bracket pool
  // But we will only "Reveal" them match by match.
  for (let t = 0; t < teamCount; t++) {
    const slots: TeamSlot[] = [];
    const usedIdsInTeam = new Set<string>();

    // Simple greedy roster fill for tournament initialization
    // For more complex constraints, a backtracking solver would be used per team
    ROLES_ORDER.forEach(role => {
       const candidate = pool.find(p => !usedIdsInTeam.has(p.id) && canPlay(p, role));
       if (candidate) {
          slots.push({ role, player: candidate });
          usedIdsInTeam.add(candidate.id);
          const idx = pool.findIndex(p => p.id === candidate.id);
          pool.splice(idx, 1);
       }
    });

    if (slots.length < 5) return null; // Failed to fill a team

    bracketTeams.push({
      id: crypto.randomUUID(),
      name: `TEAM ${String.fromCharCode(65 + t)}`,
      slots,
      color: BRACKET_COLORS[t % BRACKET_COLORS.length]
    });
  }

  const matches: TournamentMatch[] = [];
  if (teamCount === 4) {
    matches.push({ id: 'm1', teamAId: bracketTeams[0].id, teamBId: bracketTeams[1].id, winnerId: null, round: 1, matchLabel: 'SEMI-FINAL 1', isDrafted: false });
    matches.push({ id: 'm2', teamAId: bracketTeams[2].id, teamBId: bracketTeams[3].id, winnerId: null, round: 1, matchLabel: 'SEMI-FINAL 2', isDrafted: false });
    matches.push({ id: 'final', teamAId: null, teamBId: null, winnerId: null, round: 2, matchLabel: 'GRAND FINAL (BO3)', isDrafted: false });
  } else if (teamCount === 8) {
    // 4 Quarters
    for(let i=0; i<4; i++) {
        matches.push({ id: `q${i+1}`, teamAId: bracketTeams[i*2].id, teamBId: bracketTeams[i*2+1].id, winnerId: null, round: 0, matchLabel: `QUARTER-FINAL ${i+1}`, isDrafted: false });
    }
    matches.push({ id: 's1', teamAId: null, teamBId: null, winnerId: null, round: 1, matchLabel: 'SEMI-FINAL 1', isDrafted: false });
    matches.push({ id: 's2', teamAId: null, teamBId: null, winnerId: null, round: 1, matchLabel: 'SEMI-FINAL 2', isDrafted: false });
    matches.push({ id: 'final', teamAId: null, teamBId: null, winnerId: null, round: 2, matchLabel: 'GRAND FINAL (BO3)', isDrafted: false });
  }

  return { teams: bracketTeams, matches, currentMatchId: null };
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Player, MatchResult, Role, MatchHistoryEntry, TournamentBracket, TournamentMatch, BracketTeam } from './types';
import { PlayerForm } from './components/PlayerForm';
import { PlayerList } from './components/PlayerList';
import { MatchDisplay } from './components/MatchDisplay';
import { EditPlayerModal } from './components/EditPlayerModal';
import { HistoryList } from './components/HistoryList';
import { TournamentView } from './components/TournamentView';
import { generateMatch, initializeTournament } from './utils/matchmaker';
import { Button } from './components/Button';
import { BackgroundParticles } from './components/BackgroundParticles';
import { LocalClock } from './components/LocalClock';

const STORAGE_KEY_PLAYERS = 'hok_roster_data_v3';
const STORAGE_KEY_HISTORY = 'hok_match_history_v3';
const STORAGE_KEY_BRACKET = 'hok_active_bracket_v3';

export default function App() {
  const [viewMode, setViewMode] = useState<'lobby' | 'match' | 'battle' | 'bracket'>('lobby');
  const [players, setPlayers] = useState<Player[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_PLAYERS);
    return saved ? JSON.parse(saved) : [];
  });

  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_HISTORY);
    return saved ? JSON.parse(saved) : [];
  });

  const [activeBracket, setActiveBracket] = useState<TournamentBracket | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_BRACKET);
    return saved ? JSON.parse(saved) : null;
  });

  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isBracketMode, setIsBracketMode] = useState(false);
  const [bracketTeamCount, setBracketTeamCount] = useState(4);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PLAYERS, JSON.stringify(players));
  }, [players]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(matchHistory));
  }, [matchHistory]);

  useEffect(() => {
    if (activeBracket) localStorage.setItem(STORAGE_KEY_BRACKET, JSON.stringify(activeBracket));
    else localStorage.removeItem(STORAGE_KEY_BRACKET);
  }, [activeBracket]);

  const handleBatchProcess = (batchData: any[]) => {
    setPlayers(prev => {
      let updatedPlayers = [...prev];
      batchData.forEach(item => {
        const normalizedName = item.name.trim().toLowerCase();
        const existingIndex = updatedPlayers.findIndex(p => p.name.trim().toLowerCase() === normalizedName);
        if (item.action === 'bench') {
           if (existingIndex !== -1) updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], isActive: false };
        } else {
           if (existingIndex !== -1) {
              updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], roles: item.roles, isAllRoles: item.isAllRoles, isActive: true };
           } else {
              updatedPlayers.push({
                 id: crypto.randomUUID(), name: item.name, roles: item.roles, isAllRoles: item.isAllRoles, isActive: true, stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
              });
           }
        }
      });
      return updatedPlayers;
    });
  };

  const activePlayers = players.filter(p => p.isActive);

  const handleStartMatchmaking = () => {
    if (!roomId.trim() || roomId.length < 4) { setErrorMsg("Please enter Room ID."); return; }

    if (isBracketMode) {
      if (activePlayers.length < bracketTeamCount * 5) { setErrorMsg(`Need ${bracketTeamCount * 5} players.`); return; }
      const tournament = initializeTournament(activePlayers, roomId, bracketTeamCount);
      if (tournament) {
          setActiveBracket(tournament);
          setViewMode('bracket');
          setErrorMsg(null);
      } else { setErrorMsg("Failed to generate bracket."); }
    } else {
      const res = generateMatch(activePlayers, roomId, isCoachMode);
      if (res) { setCurrentMatch(res); setViewMode('match'); }
    }
  };

  const handleEnterMatch = (matchId: string) => {
    if (!activeBracket) return;
    const tMatch = activeBracket.matches.find(m => m.id === matchId);
    if (!tMatch || !tMatch.teamAId || !tMatch.teamBId) return;

    const teamA = activeBracket.teams.find(t => t.id === tMatch.teamAId)!;
    const teamB = activeBracket.teams.find(t => t.id === tMatch.teamBId)!;

    const matchResult: MatchResult = {
        roomId,
        isCoachMode: false,
        isBracketMode: true,
        azureTeam: teamA.slots,
        crimsonTeam: teamB.slots,
        bracketTeams: [teamA, teamB],
        timestamp: Date.now(),
        tournamentMatchId: matchId
    };

    setCurrentMatch(matchResult);
    setViewMode('match');
  };

  const handleMatchFinish = (winnerName: string | null, mvpId?: string, ratings?: Record<string, number>) => {
    if (!currentMatch) return;

    if (activeBracket && currentMatch.tournamentMatchId) {
       const winningTeam = currentMatch.bracketTeams?.find(t => t.name === winnerName);
       const updatedMatches = activeBracket.matches.map(m => {
          if (m.id === currentMatch.tournamentMatchId) {
             return { ...m, winnerId: winningTeam?.id || null, isDrafted: true };
          }
          return m;
       });

       // Logic to advance winner to next round
       // Quarter winners -> Semis, Semis -> Final
       const nextMatchMapping: Record<string, { targetId: string, slot: 'A' | 'B' }> = {
          'q1': { targetId: 's1', slot: 'A' }, 'q2': { targetId: 's1', slot: 'B' },
          'q3': { targetId: 's2', slot: 'A' }, 'q4': { targetId: 's2', slot: 'B' },
          'm1': { targetId: 'final', slot: 'A' }, 'm2': { targetId: 'final', slot: 'B' },
          's1': { targetId: 'final', slot: 'A' }, 's2': { targetId: 'final', slot: 'B' }
       };

       if (winningTeam && nextMatchMapping[currentMatch.tournamentMatchId]) {
          const mapping = nextMatchMapping[currentMatch.tournamentMatchId];
          const targetIdx = updatedMatches.findIndex(m => m.id === mapping.targetId);
          if (targetIdx !== -1) {
             if (mapping.slot === 'A') updatedMatches[targetIdx].teamAId = winningTeam.id;
             else updatedMatches[targetIdx].teamBId = winningTeam.id;
          }
       }

       setActiveBracket({ ...activeBracket, matches: updatedMatches });
       setViewMode('bracket');
    } else {
       setViewMode('lobby');
    }

    // Common history and stats logic...
    const historyEntry = { ...currentMatch, id: crypto.randomUUID(), winningTeam: winnerName, mvpId, ratings };
    setMatchHistory(prev => [historyEntry, ...prev]);

    setPlayers(prev => prev.map(p => {
       const isParticipant = currentMatch.azureTeam.some(s => s.player.id === p.id) || currentMatch.crimsonTeam.some(s => s.player.id === p.id);
       if (!isParticipant) return p;

       const isWinner = winnerName && (
           (currentMatch.azureTeam.some(s => s.player.id === p.id) && winnerName === 'azure') ||
           (currentMatch.crimsonTeam.some(s => s.player.id === p.id) && winnerName === 'crimson') ||
           (currentMatch.bracketTeams?.find(t => t.name === winnerName)?.slots.some(s => s.player.id === p.id))
       );

       const stats = { ...p.stats, matchesPlayed: p.stats.matchesPlayed + 1 };
       if (isWinner) { stats.wins += 1; stats.currentStreak += 1; stats.maxStreak = Math.max(stats.currentStreak, stats.maxStreak); }
       else { stats.currentStreak = 0; }

       return { ...p, stats, isLastMatchMvp: mvpId === p.id };
    }));

    setCurrentMatch(null);
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter relative flex flex-col bg-[#05090f]">
      <BackgroundParticles />
      <LocalClock />
      <div className="fixed inset-0 bg-black -z-10">
         <img src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" alt="HoK" className="absolute inset-0 w-full h-full object-cover opacity-50" />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 to-[#05090f] mix-blend-multiply"></div>
      </div>

      {viewMode === 'lobby' && (
        <main className="relative z-10 pt-16 px-4 flex-grow max-w-7xl mx-auto w-full">
           <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
              <div className="lg:col-span-4 space-y-6">
                 {activeBracket && (
                    <Button onClick={() => setViewMode('bracket')} variant="outline" className="w-full border-white text-white">RESUME ACTIVE TOURNAMENT</Button>
                 )}
                 <div className="bg-[#0a1a2f]/90 p-6 clip-corner-md border border-[#1e3a5f]">
                    <h3 className="text-xs text-[#dcb06b] font-bold uppercase tracking-widest mb-4">Lobby Config</h3>
                    <input type="text" value={roomId} onChange={(e) => setRoomId(e.target.value.replace(/\D/g,'').slice(0,4))} placeholder="ROOM ID" className="bg-black/50 border border-[#1e3a5f] p-4 text-4xl font-orbitron w-full text-center focus:border-[#dcb06b] clip-corner-sm mb-4"/>

                    <div className="grid grid-cols-2 gap-3 mb-4">
                        <button onClick={() => { setIsCoachMode(!isCoachMode); setIsBracketMode(false); }} className={`p-3 clip-corner-sm border text-[10px] font-bold tracking-widest uppercase transition-all ${isCoachMode ? 'bg-black text-[#dcb06b] border-[#dcb06b] shadow-[0_0_15px_rgba(220,176,107,0.4)]' : 'bg-[#0a1a2f] border-[#1e3a5f] text-[#4a5f78]'}`}>COACH MODE</button>
                        <button onClick={() => { setIsBracketMode(!isBracketMode); setIsCoachMode(false); }} className={`p-3 clip-corner-sm border text-[10px] font-bold tracking-widest uppercase transition-all ${isBracketMode ? 'bg-black text-white border-white shadow-[0_0_15px_rgba(255,255,255,0.4)]' : 'bg-[#0a1a2f] border-[#1e3a5f] text-[#4a5f78]'}`}>BRACKET MODE</button>
                    </div>

                    {isBracketMode && (
                        <div className="grid grid-cols-2 gap-2 mb-4">
                           {[4, 8].map(n => <button key={n} onClick={() => setBracketTeamCount(n)} className={`py-2 text-xs font-bold border clip-corner-sm ${bracketTeamCount === n ? 'bg-white text-black border-white' : 'text-white/40 border-white/10'}`}>{n} TEAMS</button>)}
                        </div>
                    )}

                    <Button onClick={handleStartMatchmaking} className="w-full" disabled={!roomId || (isBracketMode && activePlayers.length < bracketTeamCount * 5)}>START SESSION</Button>
                 </div>
                 <PlayerForm onBatchProcess={handleBatchProcess} isCoachMode={isCoachMode} />
              </div>
              <div className="lg:col-span-8">
                 <div className="tech-border p-6 bg-[#0a1a2f]/40 min-h-[500px]">
                    <PlayerList players={players} onRemove={(id) => setPlayers(prev => prev.filter(p => p.id !== id))} onToggleActive={(id) => setPlayers(prev => prev.map(p => p.id === id ? { ...p, isActive: !p.isActive } : p))} onEdit={(p) => { setEditingPlayer(p); setIsEditModalOpen(true); }} isSidebarOpen={true} />
                 </div>
                 <div className="mt-12 tech-border p-6 bg-[#0a1a2f]/40">
                    <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} />
                 </div>
              </div>
           </div>
        </main>
      )}

      {viewMode === 'bracket' && activeBracket && (
        <TournamentView bracket={activeBracket} onMatchSelect={handleEnterMatch} onReset={() => setActiveBracket(null)} onBack={() => setViewMode('lobby')} />
      )}

      {currentMatch && viewMode === 'match' && (
        <MatchDisplay match={currentMatch} activePlayers={activePlayers} initialMode="draft" onReset={() => setViewMode('bracket')} onCompleteMatch={handleMatchFinish} onReroll={() => {}} onStartBattle={() => setViewMode('battle')} />
      )}
    </div>
  );
}

