type ViewMode = 'lobby' | 'match' | 'battle' | 'bracket';

const STORAGE_KEY_PLAYERS = 'hok_roster_data_v3';
const STORAGE_KEY_HISTORY = 'hok_match_history_v3';
const STORAGE_KEY_BRACKET = 'hok_active_bracket_v3';

export default function App() {
  const [viewMode, setViewMode] = useState<ViewMode>('lobby');
  const [players, setPlayers] = useState<Player[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_PLAYERS);
    return saved ? JSON.parse(saved) : [];
  });

  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_HISTORY);
    return saved ? JSON.parse(saved) : [];
  });

  const [activeBracket, setActiveBracket] = useState<TournamentBracket | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_BRACKET);
    return saved ? JSON.parse(saved) : null;
  });

  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isBracketMode, setIsBracketMode] = useState(false);
  const [bracketTeamCount, setBracketTeamCount] = useState(4);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PLAYERS, JSON.stringify(players));
  }, [players]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(matchHistory));
  }, [matchHistory]);

  useEffect(() => {
    if (activeBracket) localStorage.setItem(STORAGE_KEY_BRACKET, JSON.stringify(activeBracket));
    else localStorage.removeItem(STORAGE_KEY_BRACKET);
  }, [activeBracket]);

  const handleBatchProcess = (batchData: any[]) => {
    setPlayers(prev => {
      let updatedPlayers = [...prev];
      batchData.forEach(item => {
        const normalizedName = item.name.trim().toLowerCase();
        const existingIndex = updatedPlayers.findIndex(p => p.name.trim().toLowerCase() === normalizedName);
        if (item.action === 'bench') {
           if (existingIndex !== -1) updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], isActive: false };
        } else {
           if (existingIndex !== -1) {
              updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], roles: item.roles, isAllRoles: item.isAllRoles, isActive: true };
           } else {
              updatedPlayers.push({
                 id: crypto.randomUUID(), name: item.name, roles: item.roles, isAllRoles: item.isAllRoles, isActive: true, stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
              });
           }
        }
      });
      return updatedPlayers;
    });
    setErrorMsg(null);
  };

  const activePlayers = players.filter(p => p.isActive);

  const handleStartMatchmaking = () => {
    if (!roomId.trim() || roomId.length !== 4) { setErrorMsg("Please enter a 4-digit Room ID."); return; }

    if (isBracketMode) {
      if (activePlayers.length < bracketTeamCount * 5) { setErrorMsg(`Need ${bracketTeamCount * 5} players.`); return; }
      const bracket = initializeTournament(activePlayers, roomId, bracketTeamCount);
      if (bracket) {
        setActiveBracket(bracket);
        setViewMode('bracket');
        setErrorMsg(null);
      } else {
        setErrorMsg("Could not form balanced teams from the current pool.");
      }
    } else {
      const required = isCoachMode ? 12 : 10;
      if (activePlayers.length < required) { setErrorMsg(`Need ${required} players.`); return; }
      const match = generateMatch(activePlayers, roomId, isCoachMode);
      if (match) {
        setCurrentMatch(match);
        setViewMode('match');
        setErrorMsg(null);
      } else {
        setErrorMsg("Failed to find valid composition.");
      }
    }
  };

  const handleEnterMatch = (matchId: string) => {
    if (!activeBracket) return;
    const bracketMatch = activeBracket.matches.find(m => m.id === matchId);
    if (!bracketMatch || !bracketMatch.teamAId || !bracketMatch.teamBId) return;

    const teamA = activeBracket.teams.find(t => t.id === bracketMatch.teamAId)!;
    const teamB = activeBracket.teams.find(t => t.id === bracketMatch.teamBId)!;

    const matchResult: MatchResult = {
      roomId,
      azureTeam: teamA.slots,
      crimsonTeam: teamB.slots,
      bracketTeams: [teamA, teamB],
      isCoachMode: false,
      isBracketMode: true,
      timestamp: Date.now(),
      tournamentMatchId: matchId
    };

    setCurrentMatch(matchResult);
    setViewMode('match');
  };

  const handleMatchFinish = (winnerName: string | null, mvpId?: string, ratings?: Record<string, number>) => {
    if (!currentMatch) return;

    const historyEntry = { ...currentMatch, id: crypto.randomUUID(), winningTeam: winnerName, mvpId, ratings };
    setMatchHistory(prev => [historyEntry, ...prev]);

    if (activeBracket && currentMatch.tournamentMatchId) {
       const winningTeamObj = currentMatch.bracketTeams?.find(t => t.name === winnerName);
       const updatedMatches = activeBracket.matches.map(m => {
         if (m.id === currentMatch.tournamentMatchId) {
           return { ...m, winnerId: winningTeamObj?.id || null, isCompleted: true };
         }
         return m;
       });

       // Logic to advance winner
       const matchMap: Record<string, { nextMatchId: string, slot: 'A' | 'B' }> = {
         'q1': { nextMatchId: 's1', slot: 'A' }, 'q2': { nextMatchId: 's1', slot: 'B' },
         'q3': { nextMatchId: 's2', slot: 'A' }, 'q4': { nextMatchId: 's2', slot: 'B' },
         'm1': { nextMatchId: 'final', slot: 'A' }, 'm2': { nextMatchId: 'final', slot: 'B' },
         's1': { nextMatchId: 'final', slot: 'A' }, 's2': { nextMatchId: 'final', slot: 'B' }
       };

       const mapping = matchMap[currentMatch.tournamentMatchId];
       if (mapping && winningTeamObj) {
         const targetMatchIdx = updatedMatches.findIndex(m => m.id === mapping.nextMatchId);
         if (targetMatchIdx !== -1) {
           if (mapping.slot === 'A') updatedMatches[targetMatchIdx].teamAId = winningTeamObj.id;
           else updatedMatches[targetMatchIdx].teamBId = winningTeamObj.id;
         }
       }

       setActiveBracket({ ...activeBracket, matches: updatedMatches });
       setViewMode('bracket');
    } else {
       setViewMode('lobby');
    }

    // Update Player Stats
    setPlayers(prev => prev.map(p => {
       const isParticipant = currentMatch.azureTeam.some(s => s.player.id === p.id) || currentMatch.crimsonTeam.some(s => s.player.id === p.id);
       if (!isParticipant) return p;

       const isWinner = winnerName && (
         (currentMatch.azureTeam.some(s => s.player.id === p.id) && winnerName === 'azure') ||
         (currentMatch.crimsonTeam.some(s => s.player.id === p.id) && winnerName === 'crimson') ||
         (currentMatch.bracketTeams?.find(t => t.name === winnerName)?.slots.some(s => s.player.id === p.id))
       );

       const stats = { ...p.stats, matchesPlayed: p.stats.matchesPlayed + 1 };
       if (isWinner) {
         stats.wins += 1;
         stats.currentStreak += 1;
         stats.maxStreak = Math.max(stats.currentStreak, stats.maxStreak);
       } else {
         stats.currentStreak = 0;
       }

       return { ...p, stats, isLastMatchMvp: mvpId === p.id, lastMatchRating: ratings?.[p.id] || 0 };
    }));

    setCurrentMatch(null);
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter relative flex flex-col bg-[#05090f]">
      <BackgroundParticles />
      <LocalClock />
      <div className="fixed inset-0 bg-black -z-10">
         <img src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" alt="HoK" className="absolute inset-0 w-full h-full object-cover opacity-50" />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 to-[#05090f] mix-blend-multiply"></div>
      </div>

      {editingPlayer && <EditPlayerModal player={editingPlayer} isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} onSave={(p) => setPlayers(prev => prev.map(old => old.id === p.id ? p : old))} />}

      {viewMode === 'lobby' && (
        <main className="relative z-10 pt-16 px-4 flex-grow max-w-7xl mx-auto w-full">
           <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
              <div className="lg:col-span-4 space-y-6">
                 {activeBracket && (
                   <Button onClick={() => setViewMode('bracket')} variant="outline" className="w-full border-white text-white">RESUME ACTIVE TOURNAMENT</Button>
                 )}
                 <div className="bg-[#0a1a2f]/90 p-6 clip-corner-md border border-[#1e3a5f]">
                    <h3 className="text-sm text-[#dcb06b] font-cinzel font-bold tracking-widest uppercase mb-4">Draft Room</h3>
                    <input type="text" value={roomId} onChange={(e) => setRoomId(e.target.value.replace(/\D/g,'').slice(0,4))} placeholder="0000" className="bg-black/40 border border-[#1e3a5f] p-4 text-5xl font-orbitron w-full text-center focus:border-[#dcb06b] clip-corner-sm mb-4"/>

                    <div className="grid grid-cols-2 gap-3 mb-4">
                        <button onClick={() => { setIsCoachMode(!isCoachMode); setIsBracketMode(false); }} className={`p-3 clip-corner-sm border text-[10px] font-bold tracking-widest uppercase transition-all ${isCoachMode ? 'bg-black text-[#dcb06b] border-[#dcb06b]' : 'bg-[#0a1a2f] border-[#1e3a5f] text-[#4a5f78]'}`}>COACH MODE</button>
                        <button onClick={() => { setIsBracketMode(!isBracketMode); setIsCoachMode(false); }} className={`p-3 clip-corner-sm border text-[10px] font-bold tracking-widest uppercase transition-all ${isBracketMode ? 'bg-black text-white border-white' : 'bg-[#0a1a2f] border-[#1e3a5f] text-[#4a5f78]'}`}>BRACKET MODE</button>
                    </div>

                    {isBracketMode && (
                        <div className="grid grid-cols-2 gap-2 mb-4">
                           {[4, 8].map(n => <button key={n} onClick={() => setBracketTeamCount(n)} className={`py-2 text-xs font-bold border clip-corner-sm ${bracketTeamCount === n ? 'bg-white text-black border-white' : 'text-white/40 border-white/10'}`}>{n} TEAMS</button>)}
                        </div>
                    )}

                    {errorMsg && <div className="p-2 mb-4 text-xs text-red-400 bg-red-900/10 border-l-2 border-red-500">{errorMsg}</div>}
                    <Button onClick={handleStartMatchmaking} className="w-full">START SESSION</Button>
                 </div>
                 <PlayerForm onBatchProcess={handleBatchProcess} isCoachMode={isCoachMode} />
              </div>
              <div className="lg:col-span-8">
                 <div className="tech-border p-6 bg-[#0a1a2f]/40 min-h-[500px]">
                    <PlayerList players={players} onRemove={(id) => setPlayers(prev => prev.filter(p => p.id !== id))} onToggleActive={(id) => setPlayers(prev => prev.map(p => p.id === id ? { ...p, isActive: !p.isActive } : p))} onEdit={(p) => { setEditingPlayer(p); setIsEditModalOpen(true); }} isSidebarOpen={true} />
                 </div>
                 <div className="mt-12 tech-border p-6 bg-[#0a1a2f]/40">
                    <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} />
                 </div>
              </div>
           </div>
        </main>
      )}

      {viewMode === 'bracket' && activeBracket && (
        <TournamentView bracket={activeBracket} onMatchSelect={handleEnterMatch} onReset={() => setActiveBracket(null)} onBack={() => setViewMode('lobby')} />
      )}

      {currentMatch && (viewMode === 'match' || viewMode === 'battle') && (
        <MatchDisplay match={currentMatch} activePlayers={activePlayers} initialMode={viewMode === 'battle' ? 'battle' : 'draft'} onReset={() => setViewMode(activeBracket ? 'bracket' : 'lobby')} onCompleteMatch={handleMatchFinish} onReroll={() => {}} onStartBattle={() => setViewMode('battle')} />
      )}
    </div>
  );
}

import React from 'react';
import { TournamentBracket, TournamentMatch, BracketTeam } from '../types';
import { Button } from './Button';

interface TournamentViewProps {
  bracket: TournamentBracket;
  onMatchSelect: (matchId: string) => void;
  onReset: () => void;
  onBack: () => void;
}

export const TournamentView: React.FC<TournamentViewProps> = ({ bracket, onMatchSelect, onReset, onBack }) => {
  const getTeam = (id: string | null) => bracket.teams.find(t => t.id === id);

  const renderMatch = (match: TournamentMatch) => {
    const teamA = getTeam(match.teamAId);
    const teamB = getTeam(match.teamBId);
    const isPlayable = teamA && teamB && !match.winnerId;
    const isFinished = !!match.winnerId;

    return (
      <div key={match.id} className={`relative group w-64 p-[1px] clip-corner-sm transition-all duration-300 ${isPlayable ? 'scale-105 shadow-[0_0_20px_rgba(255,255,255,0.15)]' : ''}`}>
         <div className={`bg-[#0a1a2f]/90 backdrop-blur-md p-4 clip-corner-sm border ${isFinished ? 'border-[#dcb06b]/50' : isPlayable ? 'border-white/40' : 'border-white/10 opacity-60'}`}>
            <div className="text-[8px] font-orbitron font-black text-white/40 tracking-widest mb-3 flex justify-between uppercase">
               <span>{match.matchLabel}</span>
               {isFinished && <span className="text-[#dcb06b]">COMPLETED</span>}
            </div>

            <div className="space-y-2">
               {[teamA, teamB].map((team, idx) => (
                  <div key={idx} className={`flex items-center justify-between p-2 rounded ${match.winnerId === team?.id ? 'bg-white/10 border border-[#dcb06b]/30' : 'bg-black/30'}`}>
                     <div className="flex items-center gap-2">
                        <div className="w-1 h-3 rounded-full" style={{ backgroundColor: team?.color || '#333' }}></div>
                        <span className={`font-orbitron text-[10px] font-bold ${team ? 'text-white' : 'text-white/20 italic'}`}>
                           {team ? team.name : 'Waiting...'}
                        </span>
                     </div>
                     {match.winnerId === team?.id && (
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 text-[#dcb06b]" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                     )}
                  </div>
               ))}
            </div>

            {isPlayable && (
               <button 
                  onClick={() => onMatchSelect(match.id)}
                  className="w-full mt-4 py-2 bg-white text-black font-cinzel font-black text-[9px] tracking-widest hover:brightness-110 transition-all clip-corner-sm"
               >
                  START DRAFT
               </button>
            )}
         </div>
      </div>
    );
  };

  const rounds = [
     bracket.matches.filter(m => m.round === 0), // Quarters
     bracket.matches.filter(m => m.round === 1), // Semis
     bracket.matches.filter(m => m.round === 2), // Finals
  ].filter(r => r.length > 0);

  return (
    <div className="min-h-screen z-10 relative flex flex-col p-8 items-center pt-24 overflow-x-auto bg-black/40 backdrop-blur-sm">
       <div className="text-center mb-16">
          <h1 className="text-6xl font-cinzel font-black text-white tracking-[0.3em] mb-4 drop-shadow-[0_0_30px_rgba(255,255,255,0.2)]">BRACKET STAGE</h1>
          <div className="flex justify-center gap-6">
             <button onClick={onBack} className="text-[10px] text-white/50 hover:text-white uppercase font-bold tracking-widest transition-all">Back to Lobby</button>
             <button onClick={onReset} className="text-[10px] text-red-500/50 hover:text-red-500 uppercase font-bold tracking-widest transition-all">Reset Tournament</button>
          </div>
       </div>

       <div className="flex items-center gap-20">
          {rounds.map((roundMatches, rIdx) => (
             <div key={rIdx} className="flex flex-col gap-12 justify-center">
                <h2 className="text-center text-[10px] font-orbitron font-black text-[#dcb06b] tracking-[0.5em] uppercase mb-4 opacity-50">ROUND {rIdx + 1}</h2>
                <div className="flex flex-col gap-16">
                   {roundMatches.map(match => renderMatch(match))}
                </div>
             </div>
          ))}
       </div>

       <div className="fixed bottom-10 left-10 max-w-xs p-4 bg-black/60 border border-white/10 clip-corner-sm backdrop-blur-md">
          <p className="text-white/40 font-orbitron text-[8px] tracking-widest font-black uppercase leading-relaxed">
            Draft matches sequentially. Winners advance to the next stage until the Grand Champion is declared.
          </p>
       </div>
    </div>
  );
};
